          const 原型定义 = 原型定义表 && 原型定义表[原型名];
          const 允许字段 = new Set(Array.isArray(原型定义 && 原型定义['允许字段']) ? 原型定义['允许字段'] : []);
          if (!原型名) 问题.push(`原型列表${index}缺少原型`);
