    function isSkillSummaryEffect(effect) {
      void effect;
      return false;
    }

    function normalizeSkillDesignerArray(value) {
      if (Array.isArray(value)) {
        return Array.from(new Set(value.map(item => toText(item, '').trim()).filter(Boolean)));
      }
      if (typeof value === 'string') {
        return Array.from(new Set(
          value
            .split(/[、,，/｜|]+/)
            .map(item => toText(item, '').trim())
            .filter(Boolean)
        ));
      }
      return [];
    }

    function buildSkillDesignerSideEffectSummary(draft = {}) {
      const rawList = Array.isArray(draft && draft.sideEffectPrototypeEffects) ? draft.sideEffectPrototypeEffects : [];
      const list = rawList.length ? 规范化技能设计台原型效果列表(rawList, '自身') : [];
      if (!list.length) return '';
      return list.map(effect => {
        const prototype = normalizeSkillUiText(effect['原型'], '原型');
        const value = normalizeSkillUiText(effect['数值'], '');
        const trigger = normalizeSkillUiText(effect['触发'], '');
        const duration = Math.max(0, Number(effect['持续回合'] || 0));
        return `${prototype}${value ? ` ${value}` : ''}${trigger ? `@${trigger}` : ''}${duration > 0 ? `/持续${duration}回合` : ''}`;
      }).join('；');
    }

    function normalizeSkillDesignerDirectionEffectList(value = []) {
      const source = Array.isArray(value) ? value : [];
      return source
        .map(effect => (effect && typeof effect === 'object' && !Array.isArray(effect) ? cloneJsonValue(effect) : null))
        .filter(effect => {
          if (!effect) return false;
          const mechanism = normalizeSkillUiText(effect['机制'], '');
          return !!mechanism && mechanism !== '系统基础' && !SKILL_SUMMARY_EFFECT_MECHANISM_SET.has(mechanism);
        });
    }

    function normalizeSkillDesignerDirectionEntry(value = {}, index = 0) {
      const source = value && typeof value === 'object' && !Array.isArray(value) ? value : {};
      const 方向ID = normalizeSkillUiText(source['方向ID'] || source.id, `方向${index + 1}`) || `方向${index + 1}`;
      const rawTargetSemantic = normalizeSkillUiText(source['方向目标语义'] || source.targetSemantic, '上下文');
      const 方向目标语义 = SKILL_DESIGNER_DIRECTION_TARGET_SEMANTIC_OPTIONS.includes(rawTargetSemantic)
        ? rawTargetSemantic
        : '上下文';
      const 方向效果数组 = normalizeSkillDesignerDirectionEffectList(source['方向效果数组'] || source.effects || []);
      return {
        方向ID,
        方向效果数组,
        方向目标语义,
      };
    }

    function normalizeSkillDesignerDirectionList(value = []) {
      const source = Array.isArray(value) ? value : [];
      const normalized = [];
      const used = new Set();
      source.forEach((entry, index) => {
        const next = normalizeSkillDesignerDirectionEntry(entry, index);
        if (!next['方向效果数组'].length) return;
        if (used.has(next['方向ID'])) {
          next['方向ID'] = `${next['方向ID']}_${index + 1}`;
        }
        used.add(next['方向ID']);
        normalized.push(next);
      });
      return normalized;
    }

    function normalizeSkillDesignerDirectionRuleEntry(value = {}, index = 0, directionIdSet = new Set()) {
      const source = value && typeof value === 'object' && !Array.isArray(value) ? value : {};
      void index;
      const rawTrigger = normalizeSkillUiText(source['触发时机'] || source.trigger, '施放前');
      const 触发时机 = SKILL_DESIGNER_DIRECTION_AUTO_TRIGGER_OPTIONS.includes(rawTrigger) ? rawTrigger : '施放前';
      const 条件 = normalizeSkillUiText(source['条件'] || source['触发条件'] || source.condition, '');
      const 切换至方向ID = normalizeSkillUiText(source['切换至方向ID'] || source.nextDirectionId, '');
      if (!切换至方向ID || !directionIdSet.has(切换至方向ID)) return null;
      return {
        触发时机,
        ...(条件 ? { 条件 } : {}),
        切换至方向ID,
      };
    }

    function normalizeSkillDesignerDirectionRuleList(value = [], directionList = []) {
      const source = Array.isArray(value) ? value : [];
      const directionIdSet = new Set((Array.isArray(directionList) ? directionList : []).map(item => normalizeSkillUiText(item && item['方向ID'], '')).filter(Boolean));
      return source
        .map((entry, index) => normalizeSkillDesignerDirectionRuleEntry(entry, index, directionIdSet))
        .filter(Boolean);
    }

    function parseSkillDesignerDirectionJson(value = '') {
      const text = normalizeSkillUiText(value, '').trim();
      if (!text) return [];
      try {
        const parsed = JSON.parse(text);
        return normalizeSkillDesignerDirectionList(Array.isArray(parsed) ? parsed : []);
      } catch (error) {
        return [];
      }
    }

    function formatSkillDesignerDirectionJson(value = []) {
      const normalized = normalizeSkillDesignerDirectionList(value);
      if (!normalized.length) return '';
      try {
        return JSON.stringify(normalized, null, 2);
      } catch (error) {
        return '';
      }
    }

    function parseSkillDesignerDirectionRuleJson(value = '', directionList = []) {
      const text = normalizeSkillUiText(value, '').trim();
      if (!text) return [];
      try {
        const parsed = JSON.parse(text);
        return normalizeSkillDesignerDirectionRuleList(Array.isArray(parsed) ? parsed : [], directionList);
      } catch (error) {
        return [];
      }
    }

    function formatSkillDesignerDirectionRuleJson(value = [], directionList = []) {
      const normalized = normalizeSkillDesignerDirectionRuleList(value, directionList);
      if (!normalized.length) return '';
      try {
        return JSON.stringify(normalized, null, 2);
      } catch (error) {
        return '';
      }
    }

    function normalizeSkillDesignerExecutionTargetModel(value = '', fallback = '单体') {
      const text = normalizeSkillUiText(value, '');
      if (!text) return normalizeSkillDesignerEffectTargetValue(fallback, '单体');
      return normalizeSkillDesignerEffectTargetValue(text, normalizeSkillDesignerEffectTargetValue(fallback, '单体'));
    }

    function normalizeSkillDesignerEffectTargetValue(value = '', fallback = '单体') {
      const text = normalizeSkillUiText(value, '');
      if (SKILL_DESIGNER_TARGET_OPTIONS.includes(text)) return text;
      if (/召唤物|召唤|分身/.test(text)) return '召唤物';
      if (/自身|施术者/.test(text)) return '自身';
      if (/全场/.test(text)) return '全场';
      if (/群体|全员|范围/.test(text)) return '群体';
      if (/单体|目标/.test(text)) return '单体';
      return SKILL_DESIGNER_TARGET_OPTIONS.includes(fallback) ? fallback : '单体';
    }

    function formatSkillDesignerSignedValue(value, asPercent = true) {
      const num = Number(value || 0);
      if (!Number.isFinite(num)) return asPercent ? '+0%' : '+0';
      const digits = Math.abs((asPercent ? num * 100 : num) % 1) < 0.0001 ? 0 : 2;
      const text = String(Number((asPercent ? num * 100 : num).toFixed(digits))).replace(/\.?0+$/, '');
      return `${num >= 0 ? '+' : ''}${text}${asPercent ? '%' : ''}`;
    }

    function parseSkillDesignerSignedValue(value) {
      const text = normalizeSkillUiText(value, '');
      if (!text) return 0;
      if (/%$/.test(text)) {
        const parsed = Number(text.replace('%', ''));
        return Number.isFinite(parsed) ? parsed / 100 : 0;
      }
      const parsed = Number(text);
      return Number.isFinite(parsed) ? parsed : 0;
    }

    function normalizeSkillDesignerEffectValue(value, action = '') {
      if (value === undefined || value === null) return value;
      if (typeof value === 'string') return normalizeSkillUiText(value, '');
      const num = Number(value);
      if (!Number.isFinite(num)) return value;
      const actionText = normalizeSkillUiText(action, '');
      if (['倍率提升', '倍率压制', '消耗提高', '消耗降低', '前摇拉长', '前摇缩短'].includes(actionText)) {
        return formatSkillDesignerSignedValue(num - 1, true);
      }
      if (actionText === '减值') return formatSkillDesignerSignedValue(-Math.abs(num), Math.abs(num) <= 1);
      if (actionText === '加值' || actionText === '持续恢复') return formatSkillDesignerSignedValue(Math.abs(num), Math.abs(num) <= 1);
      return Number(num.toFixed(4));
    }

    function 转换技能设计台原型资源字段(value = '') {
      const text = normalizeSkillUiText(value, '');
      if (text === '双资源') return ['魂力', '精神力'];
      return ({ vit: '体力', hp: '生命', sp: '魂力', men: '精神力' }[text]) || text || '魂力';
    }

    function 格式化技能设计台原型比例变化(value, 方向 = 1, 按倍率 = false) {
      const text = normalizeSkillUiText(value, '');
      if (!text) return '';
      const num = /%$/.test(text) ? Number(text.replace('%', '')) / 100 : Number(text);
      if (!Number.isFinite(num)) return text;
      const abs = Math.abs(按倍率 && num > 1 ? num - 1 : num);
      return formatSkillDesignerSignedValue(abs * (方向 < 0 ? -1 : 1), true);
    }

    function normalizeSkillDesignerTriggerValue(value = '') {
      const text = normalizeSkillUiText(value, '');
      if (!text || text === '立即生效' || text === '状态持续') return '';
      const alias = { 回合结束时: '回合结束', 状态结束后: '状态结束' };
      const normalized = alias[text] || text;
      return ['立即', '每回合', '命中后', '施放后', '回合结束', '状态结束', '常驻', '延迟'].includes(normalized) ? normalized : '';
    }

    function 规范化技能设计台打断类型(value = '') {
      const text = normalizeSkillUiText(value, '');
      if (/蓄力|吟唱|前摇/.test(text)) return '蓄力';
      if (/持续|维持/.test(text)) return '持续';
      return '释放';
    }

