      if (/^(未知|未设置|无)$/.test(resolvedTarget)) resolvedTarget = getSkillDesignerDefaultTarget(previewMeta, typeMeta.value);
      const isFusionScope = toText(previewMeta && previewMeta.scope, '') === '武魂融合技';
