    function buildSkillCoverageMatrix() {
      return Object.freeze({
        已验证夹具: Object.freeze([
          { 类目: '资源', 机制: Object.freeze(['吞噬', '能力共享']), 状态: '已验证' },
          { 类目: '条件分支', 机制: Object.freeze(['条件分支_食物自服禁用', '条件分支_神圣逆邪']), 状态: '已验证' },
          { 类目: '通用反制', 机制: Object.freeze(['机制抹消']), 状态: '已验证' },
          { 类目: '状态博弈', 机制: Object.freeze(['状态转移']), 状态: '已验证' },
          { 类目: '持续伤害', 机制: Object.freeze(['引爆持续伤害']), 状态: '已验证' },
          { 类目: '护盾博弈', 机制: Object.freeze(['斩盾', '窃取护盾']), 状态: '已验证' },
          { 类目: '链接', 机制: Object.freeze(['伤害链', '生命链接']), 状态: '已验证' },
          { 类目: '持续层数操控', 机制: Object.freeze(['延长持续伤害', '压缩持续伤害', '拆层转存']), 状态: '已验证' },
          { 类目: '资源规则', 机制: Object.freeze(['资源燃烧', '资源锁定']), 状态: '已验证' },
          { 类目: '场地', 机制: Object.freeze(['召唤与场地']), 状态: '已验证' },
          { 类目: '召唤', 机制: Object.freeze(['召唤']), 状态: '已验证' },
        ]),
        当前缺口: Object.freeze([]),
      });
    }

    window.__LWCS_SKILL_FIXTURE_LIBRARY__ = createSkillFixtureLibrary();
    window.__LWCS_SKILL_COVERAGE_MATRIX__ = buildSkillCoverageMatrix();
    window.__LWCS_GET_SKILL_COVERAGE_MATRIX__ = () => window.__LWCS_SKILL_COVERAGE_MATRIX__;
    window.__LWCS_LIST_SKILL_FIXTURES__ = () => Object.keys(window.__LWCS_SKILL_FIXTURE_LIBRARY__ || {});
    window.__LWCS_RUN_SKILL_FIXTURE__ = async function runSkillFixture(fixtureKeyOrConfig, options = {}) {
      const fixtureLibrary = window.__LWCS_SKILL_FIXTURE_LIBRARY__ || {};
      const fixture =
        typeof fixtureKeyOrConfig === 'string'
          ? fixtureLibrary[fixtureKeyOrConfig]
          : fixtureKeyOrConfig && typeof fixtureKeyOrConfig === 'object'
            ? fixtureKeyOrConfig
            : null;
      if (!fixture || typeof fixture !== 'object') throw new Error('skill_fixture_missing');

      await refreshLiveSnapshot({ force: true });
      const snapshot = liveSnapshot || lastRenderableSnapshot;
      if (!snapshot?.rootData) throw new Error('skill_fixture_snapshot_missing');
      syncMvuEditorStoreFromRoot(snapshot.rootData, { force: true });
      const 夹具玩家名 = toText(deepGet(fixture, 'battle.参战者.player.name', ''), '').trim();
      const playerName = toText(options.playerName, 夹具玩家名 || toText(snapshot.activeName, '曹德智')) || '曹德智';
      const fixtureTargetName = toText(fixture.targetName, '').trim();
      const battleData = cloneJsonValue(fixture.battle, {});
      if (battleData?.参战者?.player) battleData.参战者.player.name = playerName;

      const patches = [
        { op: 'replace', path: '/sys/玩家名', value: playerName },
        { op: 'add', path: `/char/${playerName}/自创魂技`, value: { [fixture.skillName || fixture.skillData?.name || '夹具技能']: cloneJsonValue(fixture.skillData, {}) } },
        ...(Array.isArray(fixture.patchesBefore) ? fixture.patchesBefore : []),
        { op: 'replace', path: '/world/战斗', value: battleData },
      ];
      const 恢复基线路径补丁 = [
        { op: 'replace', path: '/sys/玩家名' },
        { op: 'replace', path: `/char/${playerName}/属性` },
        { op: 'replace', path: `/char/${playerName}/决策记忆` },
        { op: 'replace', path: '/world/战斗' },
      ];
      if (fixtureTargetName) {
        恢复基线路径补丁.push({ op: 'replace', path: `/char/${fixtureTargetName}/属性` });
        恢复基线路径补丁.push({ op: 'replace', path: `/char/${fixtureTargetName}/决策记忆` });
      }
      const 恢复描述列表 = 构建技能夹具恢复描述列表(snapshot.rootData, [...patches, ...恢复基线路径补丁]);

      const originalSendToAI = window.sendToAI;
      try {
        if (typeof window.__MVU_CLOSE_DETAIL_MODAL__ === 'function') {
          try { window.__MVU_CLOSE_DETAIL_MODAL__(); } catch (error) {}
        }
        await applyJsonPatchOpsByEditor(patches, { force: true });
        await refreshLiveSnapshot({ force: true });
        await window.__MVU_OPEN_BATTLE_UI__();
        await new Promise(resolve => setTimeout(resolve, Number(options.waitMs || 220)));
        const actionName = String(fixture.skillName || fixture.skillData?.name || '').trim();
        const action = (window.BattleUI?.state?.availableActions || []).find(item => String(item?.name || '').trim() === actionName) || null;
        if (!action) throw new Error('skill_fixture_action_missing');
        if (fixtureTargetName) action.target_name = fixtureTargetName;

        window.sendToAI = () => ({ blocked: true, offline: true });
        const beforeSnapshot = cloneJsonValue(window.__MVU_GET_LIVE_SNAPSHOT__?.(), {});
        window.BattleUI.state.selectedAction = action;
        window.BattleUI.state.selectedSkillActions = [action];
        const result = window.BattleUI.submitBattleIntent();
        await new Promise(resolve => setTimeout(resolve, Number(options.settleWaitMs || 320)));
        const afterSnapshot = cloneJsonValue(window.__MVU_GET_LIVE_SNAPSHOT__?.(), {});
        const mvuUpdate = window.BattleUIBridge?.getLastMvuUpdateRequest?.() || null;
        const 摘要 = 汇总技能夹具执行结果(fixture, { beforeSnapshot, afterSnapshot, action, result, mvuUpdate }, playerName);
        const 校验 = 校验技能夹具摘要(fixture, 摘要);
        return {
          key: typeof fixtureKeyOrConfig === 'string' ? fixtureKeyOrConfig : '',
          action: { id: action.id, name: action.name, category: action.category, source: action.source_detail || action.source || '' },
          result,
          beforeSnapshot,
          afterSnapshot,
          mvuUpdate,
          summary: 摘要,
          validation: 校验,
        };
      } finally {
        window.sendToAI = originalSendToAI;
        await applyJsonPatchOpsByEditor(构建技能夹具恢复补丁(恢复描述列表), { force: true });
        await refreshLiveSnapshot({ force: true });
        if (liveSnapshot?.rootData) syncMvuEditorStoreFromRoot(liveSnapshot.rootData, { force: true });
        if (typeof window.__MVU_CLOSE_DETAIL_MODAL__ === 'function') {
          try { window.__MVU_CLOSE_DETAIL_MODAL__(); } catch (error) {}
        }
      }
    };
    window.__LWCS_RUN_SKILL_FIXTURE_BATCH__ = async function runSkillFixtureBatch(夹具键列表 = [], options = {}) {
      const fixtureLibrary = window.__LWCS_SKILL_FIXTURE_LIBRARY__ || {};
      const 待运行键列表 = Array.isArray(夹具键列表) && 夹具键列表.length ? 夹具键列表 : Object.keys(fixtureLibrary);
      const 结果项列表 = [];
      const 最大重试次数 = Math.max(0, Number(options?.retryCount ?? 1));
      for (const fixtureKey of 待运行键列表) {
        let 最佳结果 = null;
        let 最佳错误 = '';
        for (let attemptIndex = 0; attemptIndex <= 最大重试次数; attemptIndex += 1) {
          try {
            await refreshLiveSnapshot({ force: true });
            const 执行结果 = await window.__LWCS_RUN_SKILL_FIXTURE__(fixtureKey, options);
            const 当前结果 = {
              key: fixtureKey,
              ok: true,
              validation: 执行结果.validation,
              summary: 执行结果.summary,
              attempts: attemptIndex + 1,
            };
            最佳结果 = 当前结果;
            if (当前结果.validation && 当前结果.validation.通过) break;
          } catch (error) {
            最佳错误 = String(error && error.message || error || 'unknown_fixture_error');
            最佳结果 = {
              key: fixtureKey,
              ok: false,
              error: 最佳错误,
              attempts: attemptIndex + 1,
            };
          }
          await new Promise(resolve => setTimeout(resolve, Math.max(0, Number(options?.retryWaitMs || 160))));
        }
        if (最佳结果) 结果项列表.push(最佳结果);
        else
          结果项列表.push({
            key: fixtureKey,
            ok: false,
            error: 最佳错误 || 'unknown_fixture_error',
            attempts: 最大重试次数 + 1,
          });
        await new Promise(resolve => setTimeout(resolve, Math.max(0, Number(options?.betweenWaitMs || 120))));
      }
      const 通过数量 = 结果项列表.filter(item => item.ok && item.validation && item.validation.通过).length;
      return {
        total: 结果项列表.length,
        passed: 通过数量,
        failed: 结果项列表.length - 通过数量,
        items: 结果项列表,
      };
    };
    window.__LWCS_RUN_SKILL_FULL_CHECK__ = async function runSkillFullCheck(options = {}) {
      const 生成侧函数 =
        typeof window.__LWCS_RUN_GENERATION_RULE_CHECKS__ === 'function'
          ? window.__LWCS_RUN_GENERATION_RULE_CHECKS__
          : typeof __mvuBridgeRoot.__LWCS_RUN_GENERATION_RULE_CHECKS__ === 'function'
            ? __mvuBridgeRoot.__LWCS_RUN_GENERATION_RULE_CHECKS__
            : null;
      const 生成侧结果 = 生成侧函数
        ? 生成侧函数({
            品级: String(options?.品级 || 'A').trim() || 'A',
            魂环位: Math.max(1, Number(options?.魂环位 || 5)),
          })
        : { 错误: 'generation_check_unavailable' };
      const 战斗夹具键列表 =
        Array.isArray(options?.战斗夹具键列表) && options.战斗夹具键列表.length
          ? options.战斗夹具键列表
          : ['吞噬', '能力共享', '条件分支_食物自服禁用', '条件分支_神圣逆邪', '机制抹消_复苏', '机制抹消_回复机制', '机制抹消_护盾', '机制抹消_隐身', '状态转移', '引爆持续伤害', '斩盾', '窃取护盾', '召唤'];
      const 战斗侧结果 = await window.__LWCS_RUN_SKILL_FIXTURE_BATCH__(战斗夹具键列表, {
        waitMs: Number(options?.waitMs || 260),
        settleWaitMs: Number(options?.settleWaitMs || 420),
      });
      return {
        生成侧: 生成侧结果,
        战斗侧: 战斗侧结果,
        覆盖矩阵: window.__LWCS_SKILL_COVERAGE_MATRIX__ || null,
        汇总: {
          生成独占通过数: Number(生成侧结果?.汇总?.独占通过数 || 0),
          生成独占总数: Number(生成侧结果?.汇总?.独占总数 || 0),
          生成分档通过数: Number(生成侧结果?.汇总?.分档通过数 || 0),
          生成分档总数: Number(生成侧结果?.汇总?.分档总数 || 0),
          战斗通过数: Number(战斗侧结果?.passed || 0),
          战斗总数: Number(战斗侧结果?.total || 0),
        },
      };
    };
    window.__LWCS_RUN_SKILL_STABLE_CHECK__ = async function runSkillStableCheck(夹具键列表 = [], options = {}) {
      const 待运行键列表 =
        Array.isArray(夹具键列表) && 夹具键列表.length
          ? 夹具键列表
          : ['条件分支_食物自服禁用', '条件分支_神圣逆邪', '状态转移', '引爆持续伤害', '斩盾', '窃取护盾', '机制抹消_复苏', '机制抹消_护盾', '机制抹消_隐身'];
      const 结果项列表 = [];
      for (const fixtureKey of 待运行键列表) {
        await refreshLiveSnapshot({ force: true });
        const 执行结果 = await window.__LWCS_RUN_SKILL_FIXTURE__(fixtureKey, {
          waitMs: Number(options?.waitMs || 260),
          settleWaitMs: Number(options?.settleWaitMs || 420),
        });
        结果项列表.push({
          key: fixtureKey,
          ok: true,
          validation: 执行结果.validation,
          summary: 执行结果.summary,
          mode: 执行结果.result?.mode || '',
        });
        await new Promise(resolve => setTimeout(resolve, Math.max(0, Number(options?.betweenWaitMs || 220))));
      }
      const 通过数量 = 结果项列表.filter(item => item.validation && item.validation.通过).length;
      return {
        total: 结果项列表.length,
        passed: 通过数量,
        failed: 结果项列表.length - 通过数量,
        items: 结果项列表,
      };
    };
    window.__LWCS_INSPECT_PHASE2_LINKAGE__ = function inspectPhase2Linkage(options = {}) {
      const 快照 = window.__MVU_GET_LIVE_SNAPSHOT__?.() || liveSnapshot || lastRenderableSnapshot || null;
      if (!快照 || !快照.rootData) return { ok: false, reason: 'phase2_linkage_snapshot_missing' };
      const 根数据 = 快照.rootData || {};
      const 玩家名 = toText(deepGet(根数据, 'sys.玩家名', 快照.activeName), 快照.activeName);
      const 玩家任务条目 = safeEntries(deepGet(根数据, ['char', 玩家名, '记录'], {})).filter(([, item]) => item && typeof item === 'object');
      const 任务聚焦 = 玩家任务条目.find(([, item]) => !['已完成', '已放弃', '失败', '已失败'].includes(toText(item && item['状态'], '进行中'))) || 玩家任务条目[0] || null;
      const 情报条目 = safeEntries(deepGet(根数据, 'world.机密情报', {})).filter(([, item]) => item && typeof item === 'object');
      const 图鉴条目 = safeEntries(deepGet(根数据, 'world.图鉴', {})).filter(([, item]) => item && typeof item === 'object');
      const 待核实条目 = 情报条目.filter(([, item]) => toText(item && item['核实状态'], '可疑') === '待核实');
      const 情报状态统计 = 情报条目.reduce((桶, [, item]) => {
        const 状态 = toText(item && item['核实状态'], '可疑');
        桶[状态] = (桶[状态] || 0) + 1;
        return 桶;
      }, {});
      const 最近情报 = 情报条目
        .slice()
        .sort((a, b) => toNumber(deepGet(b, '1.最近核实tick', 0), 0) - toNumber(deepGet(a, '1.最近核实tick', 0), 0))[0] || null;
      const 图鉴聚焦 = 图鉴条目
        .slice()
        .sort((a, b) => toNumber(deepGet(b, '1.最近活跃tick', 0), 0) - toNumber(deepGet(a, '1.最近活跃tick', 0), 0))[0] || null;
      const 快照字段缺失 = ['当前任务路线', '当前任务风险级别', '当前任务下一节点进度', '情报待核实数量', '情报证据净值', '情报最近核实结果', '图鉴当前档位', '图鉴下一档进度', '图鉴成长倾向']
        .filter(key => !Object.prototype.hasOwnProperty.call(快照, key));
      return {
        ok: true,
        玩家名,
        任务: {
          总数: 玩家任务条目.length,
          聚焦: 任务聚焦
            ? {
                名称: 任务聚焦[0],
                状态: toText(deepGet(任务聚焦, '1.状态', '进行中'), '进行中'),
                分支: toText(deepGet(任务聚焦, '1.分支', '未判定'), '未判定'),
                风险级别: toText(deepGet(任务聚焦, '1.风险级别', '无'), '无'),
                推荐路线: toText(deepGet(任务聚焦, '1.推荐路线', '主线'), '主线'),
                当前进度: toNumber(deepGet(任务聚焦, '1.当前进度', 0), 0),
                目标进度: toNumber(deepGet(任务聚焦, '1.目标进度', 1), 1),
                情报贡献值: toNumber(deepGet(任务聚焦, '1.情报贡献值', 0), 0),
                图鉴贡献值: toNumber(deepGet(任务聚焦, '1.图鉴贡献值', 0), 0),
              }
            : null,
        },
        情报: {
          总数: 情报条目.length,
          待核实数: 待核实条目.length,
          状态统计: 情报状态统计,
          最近: 最近情报
            ? {
                名称: 最近情报[0],
                标题: toText(deepGet(最近情报, '1.标题', 最近情报[0]), 最近情报[0]),
                最近结果: toText(deepGet(最近情报, '1.最近核实结果', '无'), '无'),
                证据权重: toNumber(deepGet(最近情报, '1.证据权重', 0), 0),
                反证权重: toNumber(deepGet(最近情报, '1.反证权重', 0), 0),
                证据净值: Number((
                  toNumber(deepGet(最近情报, '1.证据权重', 0), 0)
                  - toNumber(deepGet(最近情报, '1.反证权重', 0), 0)
                ).toFixed(2)),
                来源数: Array.isArray(deepGet(最近情报, '1.证据来源列表', [])) ? deepGet(最近情报, '1.证据来源列表', []).length : 0,
              }
            : null,
        },
        图鉴: {
          总数: 图鉴条目.length,
          聚焦: 图鉴聚焦
            ? {
                名称: 图鉴聚焦[0],
                档位: toText(deepGet(图鉴聚焦, '1.图鉴档位', '初识'), '初识'),
                下一档进度: `${toNumber(deepGet(图鉴聚焦, '1.当前档经验', 0), 0)}/${toNumber(deepGet(图鉴聚焦, '1.下档需求', 0), 0)}`,
                成长倾向: toText(deepGet(图鉴聚焦, '1.成长倾向', '均衡'), '均衡'),
                任务协同系数: toNumber(deepGet(图鉴聚焦, '1.任务协同系数', 1), 1),
                情报协同系数: toNumber(deepGet(图鉴聚焦, '1.情报协同系数', 1), 1),
                最近战斗标签: toText(deepGet(图鉴聚焦, '1.最近战斗标签', '未知'), '未知'),
                战斗样本数: toNumber(deepGet(图鉴聚焦, '1.战斗样本数', 0), 0),
              }
            : null,
        },
        看板快照: {
          当前任务路线: toText(快照.当前任务路线, '无'),
          当前任务风险级别: toText(快照.当前任务风险级别, '无'),
          当前任务下一节点进度: toText(快照.当前任务下一节点进度, '--'),
          情报待核实数量: toNumber(快照.情报待核实数量, 0),
          情报证据净值: toNumber(快照.情报证据净值, 0),
          情报最近核实结果: toText(快照.情报最近核实结果, '暂无'),
          图鉴当前档位: toText(快照.图鉴当前档位, '无'),
          图鉴下一档进度: toText(快照.图鉴下一档进度, '--'),
          图鉴成长倾向: toText(快照.图鉴成长倾向, '无'),
          缺失字段: 快照字段缺失,
        },
      };
    };
    window.__LWCS_RUN_PHASE2_LINKAGE_CHECK__ = function runPhase2LinkageCheck(options = {}) {
      const 快照结果 = window.__LWCS_INSPECT_PHASE2_LINKAGE__(options);
      const 检查项 = [];
      const 追加检查 = (项目, 通过, 详情 = '') => 检查项.push({ 项目, 通过: !!通过, 详情: toText(详情, '') });
      const 允许空任务样本 = options?.允许空任务样本 !== false;
      if (!快照结果 || 快照结果.ok !== true) {
        追加检查('联动快照可用', false, toText(快照结果 && 快照结果.reason, 'unknown'));
        return {
          通过: false,
          检查项,
          检查断言: 检查项.map(item => ({ 名称: item.项目, 通过: item.通过, 详情: item.详情 })),
          快照: 快照结果 || null,
        };
      }
      const 看板缺失字段 = Array.isArray(deepGet(快照结果, '看板快照.缺失字段', [])) ? deepGet(快照结果, '看板快照.缺失字段', []) : [];
      追加检查('看板字段完整', !看板缺失字段.length, 看板缺失字段.length ? `缺失:${看板缺失字段.join(' / ')}` : '已覆盖');
      const 任务聚焦 = deepGet(快照结果, '任务.聚焦', null);
      const 存在任务样本 = !!任务聚焦;
      const 任务检查通过 = 存在任务样本 || 允许空任务样本;
      const 任务检查详情 = 存在任务样本 ? '存在聚焦任务' : (允许空任务样本 ? '当前无任务样本(按空样本通过)' : '当前无任务样本');
      追加检查('任务联动字段可见', 任务检查通过, 任务检查详情);
      const 情报最近 = deepGet(快照结果, '情报.最近', null);
      const 情报字段完整 = !情报最近 || (
        Object.prototype.hasOwnProperty.call(情报最近, '证据权重')
        && Object.prototype.hasOwnProperty.call(情报最近, '反证权重')
        && Object.prototype.hasOwnProperty.call(情报最近, '来源数')
      );
      追加检查('情报证据字段可见', 情报字段完整, 情报最近 ? `净值=${toNumber(情报最近.证据净值, 0)}` : '当前无情报样本');
      const 图鉴最近 = deepGet(快照结果, '图鉴.聚焦', null);
      const 图鉴字段完整 = !图鉴最近 || (
        Object.prototype.hasOwnProperty.call(图鉴最近, '成长倾向')
        && Object.prototype.hasOwnProperty.call(图鉴最近, '任务协同系数')
        && Object.prototype.hasOwnProperty.call(图鉴最近, '情报协同系数')
        && Object.prototype.hasOwnProperty.call(图鉴最近, '最近战斗标签')
      );
      追加检查('图鉴协同字段可见', 图鉴字段完整, 图鉴最近 ? `倾向=${toText(图鉴最近.成长倾向, '均衡')}` : '当前无图鉴样本');
      const 基准奖励币 = Math.max(1, Math.floor(Number(options?.基准奖励币 || 100000)));
      const 高收益成功币 = Math.floor(基准奖励币 * 1.45);
      const 稳妥成功币 = Math.floor(基准奖励币 * 0.85);
      const 高收益失败代价币 = Math.floor(基准奖励币 * 0.12);
      const 稳妥失败代价币 = Math.floor(基准奖励币 * 0.04);
      追加检查('路线成功收益拉开', 高收益成功币 > 稳妥成功币, `高收益=${高收益成功币} / 稳妥=${稳妥成功币}`);
      追加检查('路线失败代价拉开', 高收益失败代价币 > 稳妥失败代价币, `高收益=${高收益失败代价币} / 稳妥=${稳妥失败代价币}`);
      const 检查断言 = 检查项.map(item => ({ 名称: item.项目, 通过: item.通过, 详情: item.详情 }));
      return {
        通过: 检查项.every(item => item.通过),
        检查项,
        检查断言,
        快照: 快照结果,
        系数样本: {
          基准奖励币,
          高收益成功币,
          稳妥成功币,
          高收益失败代价币,
          稳妥失败代价币,
        },
      };
    };
    window.__LWCS_INSPECT_PHASE3_LINKAGE__ = function inspectPhase3Linkage(options = {}) {
      const 快照 = window.__MVU_GET_LIVE_SNAPSHOT__?.() || liveSnapshot || lastRenderableSnapshot || null;
      if (!快照 || !快照.rootData) return { ok: false, reason: 'phase3_linkage_snapshot_missing' };
      const 根数据 = 快照.rootData || {};
      const 系统播报 = toText(deepGet(根数据, 'sys.系统播报', ''), '');
      const 地点条目 = safeEntries(deepGet(根数据, 'world.地点', {})).filter(([, item]) => item && typeof item === 'object');
      const 库存条目 = [];
      地点条目.forEach(([地点名, 地点数据]) => {
        safeEntries(deepGet(地点数据, '商店', {})).forEach(([商店名, 商店数据]) => {
          safeEntries(deepGet(商店数据, '库存', {})).forEach(([商品名, 商品数据]) => {
            if (!商品数据 || typeof 商品数据 !== 'object') return;
            库存条目.push({
              地点: 地点名,
              商店: 商店名,
              商品: 商品名,
              库存: toNumber(商品数据 && 商品数据['库存'], 0),
              价格: toNumber(商品数据 && 商品数据['价格'], 0),
            });
          });
        });
      });
      const 情报条目 = safeEntries(deepGet(根数据, 'world.机密情报', {})).filter(([, item]) => item && typeof item === 'object');
      const 交易触发命中数 = 情报条目.filter(([, item]) => {
        const 触发来源 = toText(item && item['触发来源'], '');
        const 来源列表 = Array.isArray(item && item['证据来源列表']) ? item['证据来源列表'] : [];
        return 触发来源 === '交易' || 来源列表.some(来源 => toText(来源, '') === '交易');
      }).length;
      const 最近成交标签 = Array.from(系统播报.matchAll(/\[(买入热|卖出热|竞拍热|兑换热)\]/g))
        .map(match => toText(match && match[1], '').trim())
        .filter(Boolean)
        .slice(-1)[0] || '无';
      const 市场波动命中 = /\[市场波动\]/.test(系统播报);
      return {
        ok: true,
        看板: {
          本地供给: toText(快照 && 快照.本地供给, '无供给'),
          价格带: toText(快照 && 快照.价格带, '无'),
          最近成交影响: toText(快照 && 快照.最近成交影响, '平稳'),
        },
        市场: {
          库存总项数: 库存条目.length,
          负库存项数: 库存条目.filter(项 => toNumber(项 && 项['库存'], 0) < 0).length,
          市场波动命中,
        },
        交易情报联动: {
          最近成交标签,
          交易触发命中数,
          情报总数: 情报条目.length,
        },
      };
    };
    window.__LWCS_RUN_PHASE3_LINKAGE_CHECK__ = function runPhase3LinkageCheck(options = {}) {
      const 快照结果 = window.__LWCS_INSPECT_PHASE3_LINKAGE__(options);
      const 检查项 = [];
      const 追加检查 = (项目, 通过, 详情 = '') => 检查项.push({ 项目, 通过: !!通过, 详情: toText(详情, '') });
      const 允许空交易样本 = options?.允许空交易样本 !== false;
      if (!快照结果 || 快照结果.ok !== true) {
        追加检查('三期快照可用', false, toText(快照结果 && 快照结果.reason, 'unknown'));
        return {
          通过: false,
          检查项,
          检查断言: 检查项.map(item => ({ 名称: item.项目, 通过: item.通过, 详情: item.详情 })),
          快照: 快照结果 || null,
        };
      }
      const 看板 = 快照结果.看板 || {};
      追加检查('地图交易指标可见', !!(看板.本地供给 && 看板.价格带 && 看板.最近成交影响), `供给=${看板.本地供给 || '无'} / 价格=${看板.价格带 || '无'} / 成交=${看板.最近成交影响 || '无'}`);
      const 负库存项数 = toNumber(deepGet(快照结果, '市场.负库存项数', 0), 0);
      const 市场波动命中 = deepGet(快照结果, '市场.市场波动命中', false) === true;
      追加检查('库存不为负', 负库存项数 === 0, `负库存项=${负库存项数}`);
      追加检查('市场耗散命中可追踪', 市场波动命中 ? true : 允许空交易样本, 市场波动命中 ? '检测到[市场波动]' : (允许空交易样本 ? '本轮随机未命中(按通过处理)' : '本轮未命中'));
      const 最近成交标签 = toText(deepGet(快照结果, '交易情报联动.最近成交标签', '无'), '无');
      const 交易触发命中数 = toNumber(deepGet(快照结果, '交易情报联动.交易触发命中数', 0), 0);
      const 成交样本存在 = 最近成交标签 !== '无';
      const 联动通过 = !成交样本存在 || 交易触发命中数 > 0;
      追加检查('交易触发已并入情报链', 联动通过, 成交样本存在 ? `标签=${最近成交标签} / 命中=${交易触发命中数}` : '当前无交易热度样本');
      const 检查断言 = 检查项.map(item => ({ 名称: item.项目, 通过: item.通过, 详情: item.详情 }));
      return {
        通过: 检查项.every(item => item.通过),
        检查项,
        检查断言,
        快照: 快照结果,
      };
    };
    window.__LWCS_INSPECT_SKILL_RUNTIME__ = function inspectSkillRuntime() {
      const 当前表 = __mvuBridgeRoot.__LWCS_SKILL_MECHANISM_REGISTRY__;
      let 父级存在 = false;
      let 顶级存在 = false;
      try {
        父级存在 = !!(window.parent && window.parent !== window && window.parent.__LWCS_SKILL_MECHANISM_REGISTRY__);
      } catch (error) {}
      try {
        顶级存在 = !!(window.top && window.top !== window && window.top.__LWCS_SKILL_MECHANISM_REGISTRY__);
      } catch (error) {}
      return {
        bridgeLoaded: __mvuBridgeRoot.__MVU_LOGIC_BRIDGE_LOADED__ === true,
        bridgeRegistrySource: __mvuBridgeRoot.__LWCS_BRIDGE_REGISTRY_SOURCE__ || '',
        bridgeMvuHostSource: __mvuBridgeRoot.__LWCS_BRIDGED_MVU_HOST_SOURCE__ || '',
        registryReady: !!(当前表 && typeof 当前表 === 'object'),
        registryMechanismCount: 当前表?.机制定义 ? Object.keys(当前表.机制定义).length : 0,
        registryCurrent: !!(__mvuBridgeRoot.__LWCS_SKILL_MECHANISM_REGISTRY__),
        registryParent: 父级存在,
        registryTop: 顶级存在,
        fixtureKeys: typeof window.__LWCS_LIST_SKILL_FIXTURES__ === 'function' ? window.__LWCS_LIST_SKILL_FIXTURES__() : [],
        fixtureBatchReady: typeof window.__LWCS_RUN_SKILL_FIXTURE_BATCH__ === 'function',
        battleRegistrySource: __mvuBridgeRoot.__LWCS_BATTLE_RUNTIME_REGISTRY_SOURCE__ || '',
        battleRegistrySize: Number(__mvuBridgeRoot.__LWCS_BATTLE_RUNTIME_REGISTRY_SIZE__ || 0),
      };
    };
    window.__LWCS_BOOTSTRAP_MVU_HOST__ = () => ensureBridgedMvuHost();

    function buildRingHoverMarkup(ring) {
      return buildRingHoverCardMarkup(ring);
    }

    function buildSpiritRingGrid(rings, fallbackClass = 'ring-white') {
      const normalized = [...(rings || [])].filter(ring => ring && !ring.empty && ring.glyph && ring.glyph !== '空');
      if (!normalized.length) return '';
      return normalized.slice(0, 10).map(ring => {
        return `<div class="ring ${ring.ringClass || fallbackClass} interactive-ring">${ring.glyph}${buildRingHoverMarkup(ring)}</div>`;
      }).join('');
    }

    function renderArchiveSpiritEntry(config, isPrimary = false) {
      const head = isPrimary
        ? `<div class="dual-side-top"><div class="strip-head"><div class="strip-title cyan">武魂档案</div></div><span class="badge ${config.badgeClass || 'cyan'}">${config.badge}</span></div>`
        : `<div class="dual-side-top dual-side-top-right"><span class="badge ${config.badgeClass || 'gold'}">${config.badge}</span></div>`;

      return `${head}<div class="strip-name">${config.name}</div><div class="rings dual-grid ${isPrimary ? 'primary-rings' : 'secondary-rings'}">${buildSpiritRingGrid(config.魂环, isPrimary ? 'ring-white' : 'ring-gold')}</div>`;
    }

    function renderArchiveBloodlineEntry(config) {
      return `
        <div class="dual-side-top dual-side-top-right">
          <span class="badge ${config.badgeClass || 'gold'}">${config.badge}</span>
        </div>
        <div class="strip-name">${config.name}</div>
        <div class="rings dual-grid secondary-rings">${buildSpiritRingGrid(config.魂环, 'ring-gold')}</div>
      `;
    }

    const pageMetaMap = {
      'page-archive': { title: '档案 / 个人主控', subtitle: '详细档案、武魂轨道、社会摘要与储物入口', tag: '档案核心' },
      'page-map': { title: '星图 / 节点导航', subtitle: '当前位置、下钻路径、本地设施与动态地点', tag: '星图导航' },
      'page-world': { title: '世界 / 时空中枢', subtitle: '时间轴、偏差与拍卖警报的汇总面板', tag: '世界中枢' },
      'page-org': { title: '势力 / 矩阵沙盘', subtitle: '阵营归属、大陆格局与据点网络的视觉化入口', tag: '势力矩阵' },
      'page-terminal': { title: '终端 / 系统总线', subtitle: '系统播报、请求总线与近期见闻', tag: '系统总线' }
    };


    function setMainTab(targetId) {
      try {
        if (typeof window.__MVU_SET_TAB_STATE__ === 'function') window.__MVU_SET_TAB_STATE__(targetId);
      } catch (err) {}

      closeModal();
    }


    const initialMainTab = (() => {
      try {
        const currentTab = window.__MVU_TAB_STATE__ && typeof window.__MVU_TAB_STATE__.current === 'string'
          ? window.__MVU_TAB_STATE__.current
          : '';
        return pageMetaMap[currentTab] ? currentTab : 'page-archive';
      } catch (err) {
        return 'page-archive';
      }
    })();
    setMainTab(initialMainTab);

    function buildDynamicPreview(key) {
      if (key.startsWith('地图节点：')) {
        const nodeName = key.replace('地图节点：', '');
        return {
          title: `地图节点 / ${nodeName}`,
          summary: '从地图节点直接展开地点详情，查看这片区域的势力、补给、商路与周边可去方向。',
          highlights: ['当前节点概况', '周边势力与商路', '最近发生的地区动向'],
          duties: ['查看节点层级与地点描述', '查看掌控势力、经济与商店情况', '查看还能继续前往的周边区域'],
          actions: ['查看本地据点', '查看可用商路', '继续下钻周边区域']
        };
      }

      return {
        title: key,
        summary: '这个模块会以统一的详情页结构展开，方便直接查看核心信息。',
        highlights: ['这里会显示该模块的核心概况', '重点信息会按阅读顺序展开', '内容会保持统一结构'],
        duties: ['查看该模块的主要信息', '查看从 1级页下钻后的重型内容', '维持统一的详情阅读结构'],
        actions: ['查看重点信息', '关闭后返回上一层']
      };
    }

    var inventoryHoverPanel = null;
    var activeInventoryHoverCell = null;
    var inventoryHoverFlipY = false;
    var inventoryHoverPinned = false;

    function ensureInventoryHoverPanel() {
      if (inventoryHoverPanel) return inventoryHoverPanel;
      inventoryHoverPanel = document.createElement('div');
      inventoryHoverPanel.className = 'inventory-hover-panel';
      inventoryHoverPanel.addEventListener('mouseenter', () => {
        inventoryHoverPinned = true;
      });
      inventoryHoverPanel.addEventListener('mouseleave', () => {
        inventoryHoverPinned = false;
        hideInventoryHoverPanel();
      });
      document.body.appendChild(inventoryHoverPanel);
      return inventoryHoverPanel;
    }

    function hideInventoryHoverPanel() {
      if (inventoryHoverPinned) return;
      if (!inventoryHoverPanel) return;
      inventoryHoverPanel.classList.remove('show');
      inventoryHoverPanel.classList.remove('flip-y');
      activeInventoryHoverCell = null;
    }

    function placeInventoryHoverPanel(panel, event) {
      const gap = 18;
      const vw = window.innerWidth;
      const vh = window.innerHeight;
      const panelWidth = panel.offsetWidth || 236;
      const panelHeight = panel.offsetHeight || 168;

      let left = event.clientX + gap;
      if (left + panelWidth > vw - 12) {
        left = event.clientX - panelWidth - gap;
      }
      left = Math.max(12, Math.min(left, vw - panelWidth - 12));

      let top = event.clientY + gap;
      inventoryHoverFlipY = false;
      if (top + panelHeight > vh - 12) {
        top = event.clientY - panelHeight - gap;
        inventoryHoverFlipY = true;
      }
      top = Math.max(12, Math.min(top, vh - panelHeight - 12));

      panel.classList.toggle('flip-y', inventoryHoverFlipY);
      panel.style.left = `${left}px`;
      panel.style.top = `${top}px`;
    }

    function showInventoryHoverPanel(cell, event, forceRender = false) {
      const panel = ensureInventoryHoverPanel();
      if (forceRender || activeInventoryHoverCell !== cell) {
        const tags = (cell.dataset.hoverTags || '').split('|').filter(Boolean);
        panel.innerHTML = `
          <div class="inventory-hover-title">${cell.dataset.hoverTitle || ''}</div>
          <div class="inventory-hover-grid">
            <div class="meta-item"><b>类型</b><span>${cell.dataset.hoverType || '--'}</span></div>
            <div class="meta-item"><b>稀有度</b><span>${cell.dataset.hoverRarity || '--'}</span></div>
            <div class="meta-item"><b>数量</b><span>${cell.dataset.hoverQty || '--'}</span></div>
            <div class="meta-item"><b>有效期至</b><span>${cell.dataset.hoverExpiry || '--'}</span></div>
            <div class="meta-item"><b>来源</b><span>${cell.dataset.hoverSource || '--'}</span></div>
            <div class="meta-item"><b>说明</b><span>${cell.dataset.hoverUsage || '--'}</span></div>
          </div>
          <div class="inventory-hover-tags">${tags.filter(Boolean).map(tag => `<span class="tag-chip">${tag}</span>`).join('')}</div>
          ${cell.dataset.hoverUsable === 'true' ? `
          <button type="button" class="inventory-hover-action-btn" data-inventory-action="use" data-inventory-char="${escapeHtmlAttr(cell.dataset.hoverChar || '')}" data-inventory-item="${escapeHtmlAttr(cell.dataset.hoverTitle || '')}">
            ${htmlEscape(cell.dataset.hoverActionLabel || '使用')}
          </button>
          ` : ''}
          ${cell.dataset.hoverEquip === 'true' ? `
          <button type="button" class="inventory-hover-action-btn" data-inventory-action="equip" data-inventory-char="${escapeHtmlAttr(cell.dataset.hoverChar || '')}" data-inventory-item="${escapeHtmlAttr(cell.dataset.hoverTitle || '')}">
            穿戴装备 / 装载
          </button>
          ` : ''}
          ${cell.dataset.hoverTitle ? `
          <div class="tag-cloud armory-quick-actions mvu-detail-toolbar mvu-detail-toolbar--tight">
            <button type="button" class="inventory-hover-action-btn" data-inventory-action="discard" data-inventory-mode="one" data-inventory-char="${escapeHtmlAttr(cell.dataset.hoverChar || '')}" data-inventory-item="${escapeHtmlAttr(cell.dataset.hoverTitle || '')}">丢弃1件</button>
            ${toNumber(cell.dataset.hoverCount, 1) > 1 ? `<button type="button" class="inventory-hover-action-btn" data-inventory-action="discard" data-inventory-mode="all" data-inventory-char="${escapeHtmlAttr(cell.dataset.hoverChar || '')}" data-inventory-item="${escapeHtmlAttr(cell.dataset.hoverTitle || '')}">全部丢弃</button>` : ''}
          </div>
          ` : ''}
        `;
        activeInventoryHoverCell = cell;
      }
      panel.classList.add('show');
      placeInventoryHoverPanel(panel, event);
    }

    document.addEventListener('mousemove', (event) => {
      const eventTarget = event.target instanceof Element ? event.target : (event.target && event.target.parentElement ? event.target.parentElement : null);
      if (inventoryHoverPanel && eventTarget && inventoryHoverPanel.contains(eventTarget)) return;
      const cell = eventTarget ? eventTarget.closest('.inventory-cell[data-hover-title]') : null;
      const shellInlineHost = getShellInlineHost();
      const isShellInlineCell = !!(cell && isShellInlinePreviewActive() && shellInlineHost && shellInlineHost.contains(cell));
      if (!cell || (!(detailModal.classList.contains('show') && detailModal.contains(cell)) && !isShellInlineCell)) {
        hideInventoryHoverPanel();
        return;
      }
      inventoryHoverPinned = false;
      showInventoryHoverPanel(cell, event);
    });

    document.addEventListener('mouseleave', () => {
      inventoryHoverPinned = false;
      hideInventoryHoverPanel();
    }, true);
    document.addEventListener('scroll', hideInventoryHoverPanel, true);

    function escapeJsonPointerValue(text) {
      return String(text == null ? '' : text).split('~').join('~0').split('/').join('~1');
    }

    function normalizeMapDispatchServices(detail) {
      return Array.isArray(detail && detail.services)
        ? detail.services.map(item => toText(item, '')).filter(Boolean)
        : [];
    }

    function resolveSnapshotCharKey(snapshot, rawName) {
      const wanted = toText(rawName, '').trim();
      const chars = deepGet(snapshot, 'rootData.char', {});
      if (!wanted || !chars || typeof chars !== 'object') return '';
      if (chars[wanted]) return wanted;
      for (const [charKey, charInfo] of Object.entries(chars)) {
        const displayName = toText(charInfo && (charInfo.name || deepGet(charInfo, 'base.name', '')), charKey);
        if (displayName === wanted) return charKey;
      }
      return '';
    }

    function resolveSnapshotCharacter(snapshot, rawName) {
      const key = resolveSnapshotCharKey(snapshot, rawName);
      const chars = deepGet(snapshot, 'rootData.char', {});
      const charInfo = key && chars && typeof chars === 'object' ? (chars[key] || null) : null;
      const displayName = charInfo
        ? toText(charInfo && (charInfo.name || deepGet(charInfo, 'base.name', '')), key)
        : toText(rawName, '');
      return { key, displayName, char: charInfo };
    }

    function normalizeLocForMatch(location) {
      const raw = toText(location, '').replace(/^斗罗大陆-/, '').replace(/^斗灵大陆-/, '').trim();
      const segments = raw.split('-').filter(Boolean);
      return {
        raw,
        leaf: segments[segments.length - 1] || raw,
        segments
      };
    }

    function isLocationCompatible(currentLoc, targetLoc) {
      const current = normalizeLocForMatch(currentLoc);
      const target = normalizeLocForMatch(targetLoc);
      if (!current.raw || !target.raw) return current.raw === target.raw;
      if (current.raw === target.raw || current.leaf === target.leaf) return true;
      return current.segments.some(seg => target.segments.includes(seg));
    }

    function buildRelationInteractRequest(snapshot, actionType, rawTargetName, options = {}) {
      const currentLoc = toText(snapshot && snapshot.currentLoc, '未知地点');
      return buildMapInteractDispatchRequest(snapshot, {
        action: actionType,
        npcTarget: rawTargetName,
        target: currentLoc,
        currentLoc,
        itemUsed: toText(options.itemUsed, '无'),
        sourceLabel: '人物关系页社交互动',
        requestKind: 'relation_interaction'
      });
    }

    function buildRelationBattleInitRequest(snapshot, rawTargetName) {
      const currentLoc = toText(snapshot && snapshot.currentLoc, '未知地点');
      return buildMapBattleInitRequest(snapshot, { npcTarget: rawTargetName, target: currentLoc, currentLoc, requestKind: 'relation_sparring' });
    }

    const 武魂相关度请求锁 = new Set();

    function 提取武魂判定摘要文本(角色数据 = {}) {
      const 词条 = [];
      取角色武魂条目_桥接(角色数据).forEach(([槽位名, 武魂]) => {
        if (!武魂 || typeof 武魂 !== 'object') return;
        const 表象名称 = toText(武魂.表象名称, 槽位名);
        const 系别 = toText(武魂.系别, '未知系');
        const 属性体系 = toText(武魂.属性体系, '无');
        const 已解锁属性 = Array.isArray(武魂.已解锁属性) ? 武魂.已解锁属性.map(item => toText(item, '')).filter(Boolean) : [];
        const 描述 = toText(武魂.描述, '');
        词条.push(`${槽位名}:${表象名称}/${系别}/${属性体系}${已解锁属性.length ? `/${已解锁属性.join('|')}` : ''}${描述 ? `/${描述}` : ''}`);
      });
      return 词条.join('；') || '无武魂信息';
    }

    function 规则估算武魂相关度基础(主角数据 = {}, 对象数据 = {}, 关系数据 = {}) {
      const 主角词 = 提取武魂判定摘要文本(主角数据);
      const 对象词 = 提取武魂判定摘要文本(对象数据);
      if (!主角词 || !对象词 || 主角词 === '无武魂信息' || 对象词 === '无武魂信息') return 0;

      const 主角属性词 = new Set();
      取角色武魂条目_桥接(主角数据).forEach(([, 武魂]) => {
        if (!武魂 || typeof 武魂 !== 'object') return;
        [武魂.系别, 武魂.属性体系, ...(Array.isArray(武魂.已解锁属性) ? 武魂.已解锁属性 : [])]
          .map(item => toText(item, ''))
          .filter(Boolean)
          .forEach(item => 主角属性词.add(item));
      });
      const 对象属性词 = new Set();
      取角色武魂条目_桥接(对象数据).forEach(([, 武魂]) => {
        if (!武魂 || typeof 武魂 !== 'object') return;
        [武魂.系别, 武魂.属性体系, ...(Array.isArray(武魂.已解锁属性) ? 武魂.已解锁属性 : [])]
          .map(item => toText(item, ''))
          .filter(Boolean)
          .forEach(item => 对象属性词.add(item));
      });

      let 分数 = 0;
      const 重叠属性词 = Array.from(主角属性词).filter(item => 对象属性词.has(item));
      if (重叠属性词.length) 分数 += Math.min(40, 重叠属性词.length * 10);
      if (Array.from(主角属性词).some(item => /龙/.test(item)) && Array.from(对象属性词).some(item => /龙/.test(item))) 分数 += 15;
      if (Array.from(主角属性词).some(item => /元素/.test(item)) && Array.from(对象属性词).some(item => /元素/.test(item))) 分数 += 8;
      if (String(关系数据?.关系路线 || '').trim() === '恋人线') 分数 += 5;

      return Math.max(0, Math.min(100, Math.floor(分数)));
    }

    function 读取武魂相关度基础值_桥接(关系数据 = {}) {
      const 原值 = Number(关系数据 && 关系数据['武魂相关度基础']);
      if (!Number.isFinite(原值)) return null;
      return Math.max(0, Math.min(100, Math.floor(原值)));
    }

    function 计算关系加成值_桥接(好感度 = 0) {
      const 数值 = Number(好感度 || 0);
      if (!Number.isFinite(数值)) return 0;
      return Math.max(0, Math.min(20, Math.floor(Math.max(0, 数值) / 10)));
    }

    function 计算武魂相关度总分_桥接(关系数据 = {}) {
      const 基础值 = 读取武魂相关度基础值_桥接(关系数据);
      const 关系加成 = 计算关系加成值_桥接(toNumber(关系数据 && 关系数据['好感度'], 0));
      return Math.max(0, Math.min(100, (基础值 == null ? 0 : 基础值) + 关系加成));
    }

    function 构建关系相关度视图数据_桥接(关系数据 = {}) {
      const 好感度 = toNumber(关系数据 && 关系数据['好感度'], 0);
      const 基础值 = 读取武魂相关度基础值_桥接(关系数据);
      const 基础显示值 = 基础值 == null
        ? toText(关系数据 && 关系数据['武魂相关度基础'], '待补全')
        : String(基础值);
      const 关系加成值 = 计算关系加成值_桥接(好感度);
      const 总分值 = 计算武魂相关度总分_桥接(关系数据);
      return {
        好感度,
        基础值,
        基础显示值,
        关系加成值,
        总分值,
        融合触发状态: 总分值 >= 70 ? '可触发' : '未达阈值',
        同修效率倍率: Number((1 + 总分值 * 0.0025).toFixed(3)),
      };
    }

    function 构建武魂相关度判定系统提示(主角名, 对象名, 主角摘要, 对象摘要) {
      return [
        '你是武魂相关度判定器，只输出简短中文结论。',
        '判定口径：通常为0分，仅在武魂系别/属性体系/上下文出现明显协同时提高。',
        '基础相关度范围0-100；关系加成由系统自动计算，不由你输出。',
        `判定对象：${主角名} 与 ${对象名}。`,
        `主角武魂：${主角摘要}`,
        `对象武魂：${对象摘要}`,
        '输出格式：一句话说明判定依据，不要输出JSON，不要输出多段。'
      ].join('\n');
    }

    function 构建武魂相关度补丁路径前缀(角色键, 目标名) {
      return `/char/${escapeJsonPointerValue(角色键)}/社交/关系/${escapeJsonPointerValue(目标名)}`;
    }

    async function 尝试触发武魂相关度自动判定(snapshot, 角色键, 目标名) {
      const safe角色键 = toText(角色键, '').trim();
      const safe目标名 = toText(目标名, '').trim();
      if (!snapshot || !safe角色键 || !safe目标名) return;
      const 锁键 = `${safe角色键}::${safe目标名}`;
      if (武魂相关度请求锁.has(锁键)) return;

      const 关系数据 = deepGet(snapshot, ['rootData', 'char', safe角色键, '社交', '关系', safe目标名], null);
      if (!关系数据 || typeof 关系数据 !== 'object') return;
      const 基础值 = 读取武魂相关度基础值_桥接(关系数据);
      const 需要判定 = 基础值 == null;
      if (!需要判定) return;

      const 主角数据 = deepGet(snapshot, ['rootData', 'char', safe角色键], {}) || {};
      const 对象解析 = resolveSnapshotCharacter(snapshot, safe目标名);
      const 对象数据 = 对象解析.char || {};
      const 基础分 = 规则估算武魂相关度基础(主角数据, 对象数据, 关系数据);
      const 路径前缀 = 构建武魂相关度补丁路径前缀(safe角色键, safe目标名);
      const 预写补丁 = [
        { op: 'replace', path: `${路径前缀}/武魂相关度基础`, value: 基础分 },
      ];
      const 主角名 = toText(deepGet(主角数据, 'name', safe角色键), safe角色键);
      const 对象名 = 对象解析.displayName || safe目标名;
      const 主角摘要 = 提取武魂判定摘要文本(主角数据);
      const 对象摘要 = 提取武魂判定摘要文本(对象数据);

      武魂相关度请求锁.add(锁键);
      try {
        await dispatchUiAiRequest(
          `请判定【${主角名}】与【${对象名}】的武魂相关度基础分，通常为0，按武魂系别/属性/上下文修正。`,
          构建武魂相关度判定系统提示(主角名, 对象名, 主角摘要, 对象摘要),
          {
            requestKind: 'relation_wuhun_affinity',
            patchOps: 预写补丁,
            skipActionLock: true,
          },
        );
      } catch (error) {
      } finally {
        window.setTimeout(() => 武魂相关度请求锁.delete(锁键), 2400);
      }
    }

    function listAscensionTicketNames(snapshot) {
      return (snapshot && Array.isArray(snapshot.inventoryEntries) ? snapshot.inventoryEntries : [])
        .filter(([name, item]) => /升灵台/.test(toText(name, '')) && toNumber(item && item['数量'], 0) > 0)
        .map(([name]) => toText(name, ''))
        .filter(Boolean);
    }

    function listSoulTowerTicketNames(snapshot) {
      return (snapshot && Array.isArray(snapshot.inventoryEntries) ? snapshot.inventoryEntries : [])
        .filter(([name, item]) => {
          const safeName = toText(name, '');
          const itemType = toText(item && item['类型'], '');
          return (
            /魂灵塔/.test(safeName) &&
            (/(票|券|令|凭证)/.test(safeName) || itemType === '门票') &&
            toNumber(item && item['数量'], 0) > 0
          );
        })
        .map(([name]) => toText(name, ''))
        .filter(Boolean);
    }

    function buildInventoryConsumePatches(snapshot, charKey = '', itemName = '', quantity = 1) {
      const safeCharKey = toText(charKey, '').trim();
      const safeItemName = toText(itemName, '').trim();
      const consumeCount = Math.max(1, Math.floor(toNumber(quantity, 1)));
      if (!snapshot || !snapshot.rootData || !safeCharKey || !safeItemName) {
        return { ok: false, reason: 'inventory_consume_context_invalid', patchOps: [] };
      }
      const inventoryItem = deepGet(snapshot, ['rootData', 'char', safeCharKey, '背包', safeItemName], null);
      const currentQty = Math.max(0, Math.floor(toNumber(inventoryItem && inventoryItem['数量'], 0)));
      if (currentQty < consumeCount) {
        return { ok: false, reason: `缺少【${safeItemName}】。`, patchOps: [] };
      }
      const itemPath = `/char/${escapeJsonPointerValue(safeCharKey)}/背包/${escapeJsonPointerValue(safeItemName)}`;
      if (currentQty === consumeCount) {
        return {
          ok: true,
          patchOps: [{ op: 'remove', path: itemPath }],
        };
      }
      return {
        ok: true,
        patchOps: [{ op: 'replace', path: `${itemPath}/数量`, value: currentQty - consumeCount }],
      };
    }

    function getDefaultSoulTowerChallengeFloor(snapshot) {
      const activeChar = getActiveSnapshotCharacter(snapshot);
      return Math.min(
        SOUL_TOWER_TOTAL_FLOORS,
        Math.max(1, toNumber(deepGet(activeChar, '魂灵塔记录.最高层', 0), 0) + 1),
      );
    }

    function 解析升灵台档位(门票名 = '') {
      const safeName = toText(门票名, '');
      if (/高级/.test(safeName)) return '高级';
      if (/中级/.test(safeName)) return '中级';
      return '初级';
    }

    function 是否暴动期升灵门票(门票名 = '') {
      return /暴动期/.test(toText(门票名, ''));
    }

    function 获取升灵台强度范围(档位 = '初级', 暴动期 = false) {
      const tier = toText(档位, '初级');
      const baseMap = {
        初级: { 最小年限: 100, 最大年限: 3000, 最小等级: 20, 最大等级: 42 },
        中级: { 最小年限: 3000, 最大年限: 20000, 最小等级: 42, 最大等级: 75 },
        高级: { 最小年限: 20000, 最大年限: 100000, 最小等级: 75, 最大等级: 95 },
      };
      const base = baseMap[tier] || baseMap.初级;
      if (!暴动期) return cloneJsonValue(base, base);
      return {
        最小年限: Math.max(1, Math.floor(base.最小年限 * 0.95)),
        最大年限: Math.max(1, Math.floor(base.最大年限 * 1.12)),
        最小等级: Math.max(1, Math.floor(base.最小等级 * 0.98)),
        最大等级: Math.max(base.最小等级, Math.min(99, Math.ceil(base.最大等级 * 1.05))),
      };
    }

    function 规范化试炼状态上下文(raw = {}) {
      if (!raw || typeof raw !== 'object' || Array.isArray(raw)) return null;
      const 试炼类型 = toText(raw.试炼类型, '').trim();
      if (!['升灵台', '魂灵塔'].includes(试炼类型)) return null;
      if (试炼类型 === '升灵台') {
        const 档位 = 解析升灵台档位(raw.档位 || raw.门票名 || '');
        const 暴动期 = raw.暴动期 === true || 是否暴动期升灵门票(raw.门票名 || raw.试炼内地点 || '');
        const 门票名 = toText(raw.门票名, `${暴动期 ? '暴动期' : ''}${档位}升灵台门票`).trim();
        const 入场地点 = toText(raw.入场地点, 升灵台退出地点).trim() || 升灵台退出地点;
        const 试炼内地点 = toText(raw.试炼内地点, 构建升灵台试炼地点(档位, 暴动期)).trim() || 构建升灵台试炼地点(档位, 暴动期);
        return {
          试炼类型: '升灵台',
          门票名,
          档位,
          暴动期,
          入场地点,
          当前层: 0,
          试炼内地点,
        };
      }
      const 当前层 = Math.min(
        SOUL_TOWER_TOTAL_FLOORS,
        Math.max(1, Math.floor(toNumber(raw.当前层, 1))),
      );
      const 入场地点 = toText(raw.入场地点, 魂灵塔退出地点).trim() || 魂灵塔退出地点;
      const 门票名 = toText(raw.门票名, '魂灵塔门票').trim() || '魂灵塔门票';
      const 试炼内地点 = toText(raw.试炼内地点, 构建魂灵塔试炼地点(当前层)).trim() || 构建魂灵塔试炼地点(当前层);
      return {
        试炼类型: '魂灵塔',
        门票名,
        档位: '魂灵塔',
        暴动期: false,
        入场地点,
        当前层,
        试炼内地点,
      };
    }

    function 读取试炼状态上下文(snapshot) {
      return 规范化试炼状态上下文(解析试炼地点(读取试炼状态文本(snapshot)));
    }

    function 是否试炼状态可继续(context = null) {
      return !!规范化试炼状态上下文(context);
    }

    function 构建试炼状态上下文(options = {}) {
      const 试炼类型 = toText(options.试炼类型, '').trim();
      if (试炼类型 === '升灵台') {
        const 门票名 = toText(options.门票名, '').trim();
        const 档位 = 解析升灵台档位(门票名 || options.档位 || '初级');
        const 暴动期 = 是否暴动期升灵门票(门票名) || options.暴动期 === true;
        return {
          试炼类型: '升灵台',
          门票名: 门票名 || `${暴动期 ? '暴动期' : ''}${档位}升灵台门票`,
          档位,
          暴动期,
          入场地点: toText(options.入场地点, 升灵台退出地点).trim() || 升灵台退出地点,
          当前层: 0,
          试炼内地点: 构建升灵台试炼地点(档位, 暴动期),
        };
      }
      const 当前层 = Math.min(
        SOUL_TOWER_TOTAL_FLOORS,
        Math.max(1, Math.floor(toNumber(options.当前层, 1))),
      );
      return {
        试炼类型: '魂灵塔',
        门票名: toText(options.门票名, '魂灵塔门票').trim() || '魂灵塔门票',
        档位: '魂灵塔',
        暴动期: false,
        入场地点: toText(options.入场地点, 魂灵塔退出地点).trim() || 魂灵塔退出地点,
        当前层,
        试炼内地点: 构建魂灵塔试炼地点(当前层),
      };
    }

    function 生成升灵台战斗参数(snapshot, context = {}) {
      const safeContext = 规范化试炼状态上下文(context) || 构建试炼状态上下文({ 试炼类型: '升灵台' });
      const 强度范围 = 获取升灵台强度范围(safeContext.档位, safeContext.暴动期);
      const seedText = [
        safeContext.门票名,
        safeContext.档位,
        safeContext.暴动期 ? '暴动期' : '常规',
        safeContext.入场地点,
        toText(snapshot && snapshot.activeName, '玩家'),
      ].join('|');
      const 结果 = withTemporaryBattleRandom(seedText, rng => {
        const 对手类型 = pickTemporaryBattleItem(
          safeContext.暴动期
            ? ['魂兽', '魂师', '魂兽', '魂师']
            : ['魂兽', '魂兽', '魂师', '魂兽'],
          rng,
        ) || '魂兽';
        const 百分位 = Math.max(0, Math.min(1, Number(rng())));
        if (对手类型 === '魂师') {
          const 等级 = pickTemporaryBattleInt(强度范围.最小等级, 强度范围.最大等级, rng);
          const 对应年限 = Math.max(
            强度范围.最小年限,
            Math.min(
              强度范围.最大年限,
              Math.floor(强度范围.最小年限 + (强度范围.最大年限 - 强度范围.最小年限) * 百分位),
            ),
          );
          return {
            对手种子: {
              name: `${safeContext.档位}${safeContext.暴动期 ? '暴动期' : ''}试炼魂师`,
              单位性质: '人类',
              身份: '魂师',
              等级,
              数量: 1,
            },
            对手类型: '魂师',
            对应年限,
            百分位,
          };
        }
        const 魂兽物种 = pickTemporaryBattleItem(BATTLE_SOUL_BEAST_STANDARD_SPECIES, rng) || '龙类';
        const 品质映射 = safeContext.档位 === '高级'
          ? ['A', 'S']
          : safeContext.档位 === '中级'
            ? ['B', 'A']
            : ['C', 'B'];
        const 品质 = pickTemporaryBattleItem(品质映射, rng) || 品质映射[0] || 'C';
        const 年限 = pickTemporaryBattleInt(强度范围.最小年限, 强度范围.最大年限, rng);
        return {
          对手种子: {
            name: `${魂兽物种}拟态魂兽`,
            单位性质: '魂兽',
            标准物种: 魂兽物种,
            年限,
            品质,
            数量: 1,
          },
          对手类型: '魂兽',
          对应年限: 年限,
          百分位,
        };
      });
      return {
        对手种子: 结果.对手种子,
        对手类型: 结果.对手类型,
        killedAge: Math.max(1, Math.floor(toNumber(结果.对应年限, 强度范围.最小年限))),
        百分位: Math.max(0, Math.min(1, toNumber(结果.百分位, 0))),
        强度范围,
      };
    }

    function 构建魂灵塔守塔种子(context = {}) {
      const safeContext = 规范化试炼状态上下文(context) || 构建试炼状态上下文({ 试炼类型: '魂灵塔', 当前层: 1 });
      const floor = Math.min(SOUL_TOWER_TOTAL_FLOORS, Math.max(1, Math.floor(toNumber(safeContext.当前层, 1))));
      const seedText = `${safeContext.入场地点}|${safeContext.门票名}|tower|${floor}`;
      return withTemporaryBattleRandom(seedText, rng => buildSoulTowerGuardianSeed(floor, { rng }));
    }

    function 构建试炼入场系统提示(snapshot, context = {}, activeDisplayName = '') {
      const safeContext = 规范化试炼状态上下文(context) || {};
      const 角色名 = toText(activeDisplayName, toText(snapshot && snapshot.activeName, '当前角色'));
      const 入场地点 = toText(safeContext.入场地点, toText(snapshot && snapshot.currentLoc, '未知地点'));
      if (safeContext.试炼类型 === '升灵台') {
        const 强度范围 = 获取升灵台强度范围(safeContext.档位, safeContext.暴动期);
        return `以下内容属于前端代发的升灵台入场请求，请直接承接剧情推进，不要输出 JSON 块或变量维护指令。
[入场信息]
角色：${角色名}
地点：${入场地点}
门票：${toText(safeContext.门票名, '升灵台门票')}
档位：${toText(safeContext.档位, '初级')}
暴动期：${safeContext.暴动期 ? '是' : '否'}
[强度约束]
本场潜在对手可以是魂兽或魂师，战力必须限制在该档位区间：
- 对应年限区间：${formatNumber(强度范围.最小年限)}~${formatNumber(强度范围.最大年限)}
- 对应魂师等级区间：${强度范围.最小等级}~${强度范围.最大等级}
非暴动期魂师胜利不提供升灵奖励；暴动期魂师胜利可提供随机升灵奖励。
[流程要求]
本轮先描写入场与试炼氛围推进，入场不等于直接开战。只有当剧情推进到明确交锋节点时，才输出 battle 模块意图触发战斗。`;
      }
      const floor = Math.min(SOUL_TOWER_TOTAL_FLOORS, Math.max(1, Math.floor(toNumber(safeContext.当前层, 1))));
      const gateMeta = getSoulTowerGateMeta(floor);
      return `以下内容属于前端代发的魂灵塔入场请求，请直接承接剧情推进，不要输出 JSON 块或变量维护指令。
[入场信息]
角色：${角色名}
地点：${入场地点}
门票：${toText(safeContext.门票名, '魂灵塔门票')}
当前层：第${floor}层（${gateMeta.gateLabel}，${gateMeta.gateRangeLabel}）
[强度约束]
守塔对象强度必须匹配第${floor}层规则，不得越级漂移。
[流程要求]
本轮先写入塔后的剧情与对峙推进，入塔不等于立即开战。只有在剧情明确进入战斗节点时，才输出 battle 模块意图。`;
    }

    async function 登记试炼入场并推进剧情(snapshot, options = {}) {
      const sourceSnapshot = snapshot && snapshot.rootData ? snapshot : (liveSnapshot || lastRenderableSnapshot);
      if (!sourceSnapshot || !sourceSnapshot.rootData) throw new Error('当前快照未就绪，无法登记试炼入场。');
      if (!isSnapshotPlayerControlled(sourceSnapshot)) throw new Error('旁观视角不可操作。');
      if (deepGet(sourceSnapshot, 'rootData.world.战斗.进行中', false)) {
        throw new Error('当前仍在战斗中，无法登记新的试炼入场。');
      }
      const 当前试炼 = 读取试炼状态上下文(sourceSnapshot);
      if (当前试炼) {
        throw new Error(`当前仍在${当前试炼.试炼类型}流程中，请先结束后再进入新试炼。`);
      }
      const 试炼类型 = toText(options.试炼类型, '').trim();
      if (!['升灵台', '魂灵塔'].includes(试炼类型)) throw new Error('试炼类型无效。');
      const activeCharKey = resolveSnapshotCharKey(sourceSnapshot, toText(sourceSnapshot.activeName, '')) || toText(sourceSnapshot.activeName, '');
      if (!activeCharKey) throw new Error('缺少角色信息。');
      const entryLocation = toText(options.entryLocation, 读取当前角色位置(sourceSnapshot)).trim();
      if (是否试炼内地点(entryLocation)) throw new Error('当前仍在试炼区域，无法重复入场。');
      let selectedTicket = '';
      let trialContext = null;
      if (试炼类型 === '升灵台') {
        if (!isTransmissionTowerEntryLocation(entryLocation)) throw new Error('升灵台只能从传灵塔入口进入。');
        const ascensionTickets = listAscensionTicketNames(sourceSnapshot);
        selectedTicket = toText(options.ticketName, ascensionTickets[0] || '').trim();
        if (!selectedTicket) throw new Error('缺少升灵台门票。');
        trialContext = 构建试炼状态上下文({
          试炼类型,
          门票名: selectedTicket,
          入场地点: entryLocation,
        });
      } else {
        if (!isSoulTowerHeadquartersLocation(entryLocation)) throw new Error('魂灵塔只能从史莱克城传灵塔总部进入。');
        const activeChar = getActiveSnapshotCharacter(sourceSnapshot);
        if (!isSoulTowerEligibleCharacterData(activeChar)) throw new Error('当前角色不满足魂灵塔入塔条件。');
        const soulTowerTickets = listSoulTowerTicketNames(sourceSnapshot);
        selectedTicket = toText(options.ticketName, soulTowerTickets[0] || '').trim();
        if (!selectedTicket) throw new Error('缺少魂灵塔门票。');
        trialContext = 构建试炼状态上下文({
          试炼类型,
          门票名: selectedTicket,
          入场地点: entryLocation,
          当前层: Math.min(
            SOUL_TOWER_TOTAL_FLOORS,
            Math.max(1, Math.floor(toNumber(options.floor, getDefaultSoulTowerChallengeFloor(sourceSnapshot)))),
          ),
        });
      }
      const ticketConsumeResult = buildInventoryConsumePatches(sourceSnapshot, activeCharKey, selectedTicket, 1);
      if (!ticketConsumeResult.ok) throw new Error(ticketConsumeResult.reason || `缺少【${selectedTicket}】门票。`);
      const 试炼内地点 = trialContext.试炼类型 === '魂灵塔'
        ? 构建魂灵塔试炼地点(trialContext.当前层)
        : 构建升灵台试炼地点(trialContext.档位, trialContext.暴动期);
      const 清理后战斗数据 = (() => {
        const rawBattle = cloneJsonValue(deepGet(sourceSnapshot, 'rootData.world.战斗', {}), {});
        const nextBattle = rawBattle && typeof rawBattle === 'object' && !Array.isArray(rawBattle) ? rawBattle : {};
        nextBattle.试炼状态 = trialContext.试炼类型 === '魂灵塔'
          ? 构建魂灵塔试炼地点(trialContext.当前层)
          : 构建升灵台试炼地点(trialContext.档位, trialContext.暴动期);
        if (trialContext.试炼类型 === '魂灵塔') {
          nextBattle.floor = trialContext.当前层;
        }
        return nextBattle;
      })();
      const 播报前缀 = trialContext.试炼类型 === '升灵台' ? '升灵台' : '魂灵塔';
      const 播报正文 = trialContext.试炼类型 === '升灵台'
        ? `${toText(sourceSnapshot.activeName, activeCharKey)} 已进入${trialContext.档位}${trialContext.暴动期 ? '暴动期' : ''}升灵台，等待剧情推进触发战斗。`
        : `${toText(sourceSnapshot.activeName, activeCharKey)} 已进入魂灵塔第${trialContext.当前层}层，等待剧情推进触发战斗。`;
      await applyJsonPatchOpsByEditor([
        ...ticketConsumeResult.patchOps,
        { op: 'replace', path: '/world/战斗', value: 清理后战斗数据 },
        { op: 'add', path: `/char/${escapeJsonPointerValue(activeCharKey)}/状态/位置`, value: 试炼内地点 },
        { op: 'replace', path: '/sys/系统播报', value: `[${播报前缀}] ${播报正文}` },
      ], { force: true });
      await refreshLiveSnapshot({ force: true });
      const latestSnapshot = liveSnapshot || sourceSnapshot;
      const activeDisplayName = toText(deepGet(latestSnapshot, 'activeChar.name', latestSnapshot.activeName), latestSnapshot.activeName);
      const dispatchRequest = {
        playerInput: trialContext.试炼类型 === '升灵台'
          ? `我进入了${trialContext.档位}${trialContext.暴动期 ? '暴动期' : ''}升灵台，准备开始本次试炼。`
          : `我进入魂灵塔第${trialContext.当前层}层，准备开始本层挑战。`,
        systemPrompt: 构建试炼入场系统提示(latestSnapshot, trialContext, activeDisplayName),
        requestKind: trialContext.试炼类型 === '升灵台' ? 'trial_entry_ascension' : 'trial_entry_tower',
      };
      const dispatchResult = await dispatchUiAiRequest(
        dispatchRequest.playerInput,
        dispatchRequest.systemPrompt,
        { requestKind: dispatchRequest.requestKind },
      );
      if (!dispatchResult?.ok) {
        throw new Error('入场登记成功，但剧情推进触发失败，请重试推进。');
      }
      return {
        ok: true,
        context: trialContext,
        requestKind: dispatchRequest.requestKind,
        dispatchResult,
      };
    }

    function splitSoulSpiritTargetValue(value) {
      const raw = toText(value, '').trim();
      if (!raw || !raw.includes('::')) return { spiritKey: '', soulSpiritKey: '' };
      const [spiritKey, soulSpiritKey] = raw.split('::');
      return {
        spiritKey: toText(spiritKey, '').trim(),
        soulSpiritKey: toText(soulSpiritKey, '').trim(),
      };
    }

    function getTrialRingColorByAge(age = 0) {
      const value = Math.max(0, Math.floor(Number(age) || 0));
      if (value >= 100000) return '红';
      if (value >= 10000) return '黑';
      if (value >= 1000) return '紫';
      if (value >= 100) return '黄';
      return '白';
    }

    function getDonateBasePrice(itemName) {
      const safeName = toText(itemName, '');
      if (/天锻|四字|红级|十万年/.test(safeName)) return 100000000;
      if (/魂锻|三字|黑级|万年/.test(safeName)) return 10000000;
      if (/灵锻|二字|紫级|千年/.test(safeName)) return 1000000;
      if (/千锻|一字|黄级|百年/.test(safeName)) return 100000;
      return 10000;
    }

    function getDonateTalentMultiplier(talentTier) {
      return {
        '绝世妖孽': 2.0,
        '顶级天才': 1.8,
        '天才': 1.5,
        '优秀': 1.2,
        '正常': 1.0,
        '劣等': 0.5,
      }[toText(talentTier, '')] || 1.0;
    }

    function getDonateRewardLabel(targetFaction) {
      if (targetFaction === '史莱克学院') return '学院积分';
      if (targetFaction === '战神殿' || targetFaction === '血神军团') return '战功';
      return '唐门积分';
    }

    function buildDonateDispatchRequest(snapshot, options = {}) {
      if (!snapshot || !snapshot.rootData) return null;
      if (!isSnapshotPlayerControlled(snapshot)) return null;
      const activeKey = resolveSnapshotCharKey(snapshot, toText(snapshot.activeName, ''));
      if (!activeKey) return null;
      const itemName = toText(options.itemName, '').trim();
      const targetFaction = toText(options.targetFaction, '').trim();
      const quantity = Math.max(1, Math.floor(toNumber(options.quantity, 1)));
      if (!itemName || !targetFaction || itemName === '无' || targetFaction === '无') return null;
      const ownedCount = toNumber(deepGet(snapshot, ['activeChar', '背包', itemName, '数量'], 0), 0);
      if (ownedCount < quantity) return null;
      const chars = deepGet(snapshot, 'rootData.char', {});
      const activeChar = chars && typeof chars === 'object' ? (chars[activeKey] || {}) : {};
      const activeName = toText(activeChar && (activeChar.name || deepGet(activeChar, 'base.name', '')), toText(snapshot.activeName, activeKey));
      const currentLoc = toText(deepGet(activeChar, '状态.位置', snapshot.currentLoc || '当前位置'), snapshot.currentLoc || '当前位置').replace(/^斗罗大陆-/, '').replace(/^斗灵大陆-/, '');
      const talentTier = toText(deepGet(activeChar, '属性.talent_tier', '正常'), '正常');
      const basePrice = getDonateBasePrice(itemName);
      const talentMultiplier = getDonateTalentMultiplier(talentTier);
      const totalValue = basePrice * quantity;
      const pointsEarned = Math.floor((totalValue / 1000) * talentMultiplier);
      const rewardLabel = getDonateRewardLabel(targetFaction);
      const systemPrompt = `以下内容属于前端代发的阵营捐献请求，请直接承接剧情与后续处理，不要输出 JSON 块或变量维护指令。

[捐献摘要]
角色：${activeName}
地点：${currentLoc}
目标势力：${targetFaction}
物品：${itemName}
数量：${quantity}
当前库存：${ownedCount}
基准估值：${formatNumber(basePrice)} / 件
总估值：${formatNumber(totalValue)}
天赋档位：${talentTier}
天赋系数：${talentMultiplier}
预计获得：${formatNumber(pointsEarned)} ${rewardLabel}

请结合当前地点、角色所属势力关系、物资价值与阵营流程，自然写出捐献受理、核验和反馈；若当场无法受理，也请明确给出阻碍原因。
若捐献成立，请按以上估值结果发放 ${formatNumber(pointsEarned)} ${rewardLabel}。`;
      return {
        playerInput: `我想向【${targetFaction}】捐献【${itemName}】×${quantity}。`,
        systemPrompt,
        requestKind: 'faction_donate'
      };
    }

    function buildQuestDispatchRequest(snapshot, actionType, options = {}) {
      if (!snapshot || !snapshot.rootData) return null;
      if (!isSnapshotPlayerControlled(snapshot)) return null;
      const activeKey = resolveSnapshotCharKey(snapshot, toText(snapshot.activeName, ''));
      if (!activeKey) return null;
      const questName = toText(options.questName, '').trim();
      if (!questName || questName === '无') return null;

      const chars = deepGet(snapshot, 'rootData.char', {});
      const activeChar = chars && typeof chars === 'object' ? (chars[activeKey] || {}) : {};
      const activeName = toText(activeChar && (activeChar.name || deepGet(activeChar, 'base.name', '')), toText(snapshot.activeName, activeKey));
      const currentLoc = toText(deepGet(activeChar, '状态.位置', snapshot.currentLoc || '当前位置'), snapshot.currentLoc || '当前位置').replace(/^斗罗大陆-/, '').replace(/^斗灵大陆-/, '');
      const boardEntry = deepGet(snapshot, ['rootData', 'world', '委托板', questName], null);
      const recordEntry = deepGet(snapshot, ['activeChar', '记录', questName], null);
      const boardTitle = toText(boardEntry && boardEntry['标题'], questName);
      const boardFrameDesc = toText(boardEntry && boardEntry['框架描述'], '无');
      const boardHiddenDesc = toText(boardEntry && boardEntry['描述'], boardFrameDesc);
      const boardStatus = toText(boardEntry && boardEntry['状态'], '待接取');
      const recordStatus = toText(recordEntry && recordEntry['状态'], '进行中');

      let questAction = '';
      let questDesc = '';
      let requiredCount = 1;
      let rewardCoin = 0;
      let rewardRep = 0;
      let progressAdd = Math.max(1, Math.floor(toNumber(options.progressAdd, 1)));
      let statusAction = '任务处理中';
      let requestLabel = '';
      let analysisLabel = '';
      let playerInput = '';
      let extraRequirement = '';

      if (actionType === 'accept') {
        if (!boardEntry || boardStatus !== '待接取') return null;
        questAction = '接取';
        questDesc = boardHiddenDesc !== '无' ? boardHiddenDesc : boardFrameDesc;
        requiredCount = Math.max(1, Math.floor(toNumber(boardEntry && boardEntry['目标进度'], 1)));
        rewardCoin = Math.max(0, Math.floor(toNumber(boardEntry && boardEntry['奖励币'], 0)));
        rewardRep = Math.max(0, Math.floor(toNumber(boardEntry && boardEntry['奖励声望'], 0)));
        statusAction = '接取委托';
        requestLabel = `[任务接取申请] ${activeName} 在【${currentLoc}】准备接取委托【${boardTitle}】。`;
        analysisLabel = 'Quest accept request initialized from task panel.';
        playerInput = `我想接取委托板上的【${boardTitle}】。`;
        extraRequirement = `这是一个接取前只公开框架的委托。你现在可以在剧情里正常披露详细目标，但必须保留 任务请求.任务描述 = ${questDesc}、目标进度 = ${requiredCount}、奖励币 = ${rewardCoin}、奖励声望 = ${rewardRep}。`;
      } else if (actionType === 'submit') {
        if (!recordEntry || ['已完成', '已放弃', '失败', '已失败'].includes(recordStatus)) return null;
        questAction = '提交';
        questDesc = toText(recordEntry && recordEntry['描述'], '无');
        requiredCount = Math.max(1, Math.floor(toNumber(recordEntry && recordEntry['目标进度'], 1)));
        rewardCoin = Math.max(0, Math.floor(toNumber(recordEntry && recordEntry['奖励币'], 0)));
        rewardRep = Math.max(0, Math.floor(toNumber(recordEntry && recordEntry['奖励声望'], 0)));
        progressAdd = 0;
        statusAction = '提交任务';
        requestLabel = `[任务提交申请] ${activeName} 在【${currentLoc}】准备提交任务【${questName}】。`;
        analysisLabel = 'Quest submit request initialized from task panel.';
        playerInput = `我想提交当前任务【${questName}】。`;
        extraRequirement = '你必须保留 任务请求.动作 = 提交，并保留 任务名称、任务描述、目标进度、奖励币、奖励声望 这些字段，使 MVU 后续可以按进度进行结算。';
      } else if (actionType === 'abandon') {
        if (!recordEntry || ['已完成', '已放弃', '失败', '已失败'].includes(recordStatus)) return null;
        questAction = '放弃';
        questDesc = toText(recordEntry && recordEntry['描述'], '无');
        requiredCount = Math.max(1, Math.floor(toNumber(recordEntry && recordEntry['目标进度'], 1)));
        rewardCoin = Math.max(0, Math.floor(toNumber(recordEntry && recordEntry['奖励币'], 0)));
        rewardRep = Math.max(0, Math.floor(toNumber(recordEntry && recordEntry['奖励声望'], 0)));
        progressAdd = 0;
        statusAction = '放弃任务';
        requestLabel = `[任务放弃申请] ${activeName} 在【${currentLoc}】准备放弃任务【${questName}】。`;
        analysisLabel = 'Quest abandon request initialized from task panel.';
        playerInput = `我想放弃当前任务【${questName}】。`;
        extraRequirement = '你必须保留 任务请求.动作 = 放弃，并保留 任务名称、任务描述、目标进度、奖励币、奖励声望 这些字段，使 MVU 后续可以正确回滚委托板状态。';
      } else if (actionType === 'progress') {
        if (!recordEntry || ['已完成', '已放弃', '失败', '已失败'].includes(recordStatus)) return null;
        questAction = '更新进度';
        questDesc = toText(recordEntry && recordEntry['描述'], '无');
        requiredCount = Math.max(1, Math.floor(toNumber(recordEntry && recordEntry['目标进度'], 1)));
        rewardCoin = Math.max(0, Math.floor(toNumber(recordEntry && recordEntry['奖励币'], 0)));
        rewardRep = Math.max(0, Math.floor(toNumber(recordEntry && recordEntry['奖励声望'], 0)));
        statusAction = '任务推进';
        requestLabel = `[任务进度申请] ${activeName} 在【${currentLoc}】推进任务【${questName}】，计划增加 ${progressAdd} 点进度。`;
        analysisLabel = 'Quest progress request initialized from task panel.';
        playerInput = `我想推进任务【${questName}】的进度。`;
        extraRequirement = `你必须保留 任务请求.动作 = 更新进度 与 进度增量 = ${progressAdd}，并保留 任务名称、任务描述、目标进度、奖励币、奖励声望 这些字段。`;
      } else {
        return null;
      }

      const patchOps = [
        { op: 'replace', path: `/char/${escapeJsonPointerValue(activeKey)}/任务请求`, value: { 动作: questAction, 任务名称: questName, 任务描述: questDesc, 进度增量: progressAdd, 目标进度: requiredCount, 奖励币: rewardCoin, 奖励声望: rewardRep } },
        { op: 'replace', path: `/char/${escapeJsonPointerValue(activeKey)}/状态/行动`, value: statusAction },
        { op: 'replace', path: '/sys/系统播报', value: requestLabel }
      ];
      const systemPrompt = `以下内容属于前端已经完成的任务请求初始化，不要在正文直接复述“JSONPatch / 系统分析 / 仲裁日志”等术语。

${requestLabel}

[任务要求]
${extraRequirement}

任务请求与当前行动已经由脚本写入 MVU，正文只承接剧情表现，不要重复输出这批变量更新。`;

      return {
        playerInput,
        systemPrompt,
        requestKind: '任务请求',
        patchOps
      };
    }


    function buildFactionAffairConsoleHtml(snapshot, preferredFactionName = '') {
      const pendingDonateItem = toText(deepGet(snapshot, 'activeChar.捐献请求.物品名称', '无'), '无');
      const pendingDonateFaction = toText(deepGet(snapshot, 'activeChar.捐献请求.目标势力', '无'), '无');
      const pendingDonateQty = Math.max(1, toNumber(deepGet(snapshot, 'activeChar.捐献请求.数量', 1), 1));
      const factionNames = [];
      [preferredFactionName, pendingDonateFaction, ...(snapshot.势力 || []).map(([name]) => name), '唐门', '史莱克学院', '战神殿', '传灵塔', '联邦军方', '血神军团', '圣灵教'].forEach(name => {
        const text = toText(name, '').trim();
        if (text && text !== '无' && !factionNames.includes(text)) factionNames.push(text);
      });
      const donationEntries = (snapshot.inventoryEntries || []).filter(([, item]) => toNumber(item && item['数量'], 0) > 0).slice(0, 50);
      const donationOptionsHtml = donationEntries.length
        ? donationEntries.map(([name, item]) => `<option value="${escapeHtmlAttr(name)}" ${name === pendingDonateItem ? 'selected' : ''}>${htmlEscape(`${name} ×${toNumber(item && item['数量'], 0)}`)}</option>`).join('')
        : '<option value="">暂无可捐献物品</option>';
      const defaultDonateFaction = pendingDonateFaction !== '无' ? pendingDonateFaction : (preferredFactionName || factionNames[0] || '');
      const pendingSummary = pendingDonateItem !== '无' ? `${pendingDonateItem} × ${pendingDonateQty} / ${pendingDonateFaction}` : '无';
      const isPlayerControlled = isSnapshotPlayerControlled(snapshot);
      if (!isPlayerControlled) {
        return `
          <div class="archive-card dossier-card dossier-console-card request-console-card">
            <div class="archive-card-head"><div class="archive-card-title">阵营事务台</div><span class="dossier-pill warn">旁观</span></div>
            <section class="dossier-section">
              <div class="dossier-section-title">当前状态</div>
              ${makeDossierRows([
                { label: '挂起事务', value: htmlEscape(pendingSummary) },
                { label: '当前视角', value: '旁观' },
              ], 'dossier-row-grid--single')}
            </section>
            <section class="dossier-section">
              <div class="dossier-section-title">主要贡献池</div>
              <div class="dossier-contrib-grid">
                ${makeDossierMeter('唐门', htmlEscape(formatNumber(deepGet(snapshot, 'activeChar.财富.唐门积分', 0))), ratioPercent(deepGet(snapshot, 'activeChar.财富.唐门积分', 0), 1000), 'dossier-meter--cyan')}
                ${makeDossierMeter('史莱克学院', htmlEscape(formatNumber(deepGet(snapshot, 'activeChar.财富.学院积分', 0))), ratioPercent(deepGet(snapshot, 'activeChar.财富.学院积分', 0), 1000), 'dossier-meter--green')}
                ${makeDossierMeter('战神殿/军方', htmlEscape(formatNumber(deepGet(snapshot, 'activeChar.财富.战功', 0))), ratioPercent(deepGet(snapshot, 'activeChar.财富.战功', 0), 1000), 'dossier-meter--red')}
              </div>
            </section>
          </div>
        `;
      }
      return `
        <div class="archive-card dossier-card dossier-console-card request-console-card">
          <div class="archive-card-head"><div class="archive-card-title">阵营事务台</div><span class="dossier-pill ${preferredFactionName ? 'live' : 'warn'}">${htmlEscape(preferredFactionName || '未加入')}</span></div>
          <section class="dossier-section">
            <div class="dossier-section-title">挂起事务</div>
            ${makeDossierRows([{ label: '当前排队', value: htmlEscape(pendingSummary) }], 'dossier-row-grid--single')}
          </section>
          <section class="dossier-section">
            <div class="dossier-section-title">物资捐献</div>
            <div class="dossier-form-grid">
              <div class="dossier-form-row request-console-row request-console-row--donate dossier-form-row--donate">
                <select class="request-console-input" data-faction-input="donateFaction">${factionNames.map(name => `<option value="${escapeHtmlAttr(name)}" ${name === defaultDonateFaction ? 'selected' : ''}>${htmlEscape(name)}</option>`).join('')}</select>
                <select class="request-console-input" data-faction-input="donateItem" ${donationEntries.length ? '' : 'disabled'}>${donationOptionsHtml}</select>
                <input type="number" min="1" class="request-console-input" data-faction-input="donateQty" value="${escapeHtmlAttr(String(pendingDonateQty))}" placeholder="数量" />
                <button type="button" class="relation-action-btn faction-action-btn" data-faction-action="donate" ${donationEntries.length ? '' : 'disabled'}>提交捐献</button>
              </div>
            </div>
          </section>
          <section class="dossier-section">
            <div class="dossier-section-title">主要贡献池</div>
            <div class="dossier-contrib-grid">
              ${makeDossierMeter('唐门', htmlEscape(formatNumber(deepGet(snapshot, 'activeChar.财富.唐门积分', 0))), ratioPercent(deepGet(snapshot, 'activeChar.财富.唐门积分', 0), 1000), 'dossier-meter--cyan')}
              ${makeDossierMeter('史莱克学院', htmlEscape(formatNumber(deepGet(snapshot, 'activeChar.财富.学院积分', 0))), ratioPercent(deepGet(snapshot, 'activeChar.财富.学院积分', 0), 1000), 'dossier-meter--green')}
              ${makeDossierMeter('战神殿/军方', htmlEscape(formatNumber(deepGet(snapshot, 'activeChar.财富.战功', 0))), ratioPercent(deepGet(snapshot, 'activeChar.财富.战功', 0), 1000), 'dossier-meter--red')}
            </div>
          </section>
        </div>
      `;
    }

    function buildFactionRelationDossierList(orgName, orgData, options = {}) {
      const { max = 6, emptyTitle = '暂无阵营关系', emptyDesc = '当前未记录对外关系。' } = options || {};
      const safeOrgName = toText(orgName, '').trim();
      const relationEntries = safeEntries(deepGet(orgData, '关系', {})).slice(0, Math.max(1, max));
      if (!relationEntries.length) {
        return `<div class="dossier-empty-note">${htmlEscape(emptyTitle)}：${htmlEscape(emptyDesc)}</div>`;
      }
      return makeDossierList(relationEntries.map(([relationName, relationData]) => {
        const safeRelData = relationData && typeof relationData === 'object' ? relationData : {};
        const relationMeta = buildFactionRelationMeta(relationName, safeRelData);
        const relationField = Object.prototype.hasOwnProperty.call(safeRelData, '态度')
          ? '态度'
          : (Object.prototype.hasOwnProperty.call(safeRelData, '关系') ? '关系' : '态度');
        const relationValue = toText(deepGet(safeRelData, relationField, relationMeta.attitude), relationMeta.attitude);
        const detailText = safeEntries(safeRelData)
          .filter(([key]) => !['态度', '关系'].includes(toText(key, '')))
          .map(([key, value]) => {
            if (value && typeof value === 'object') return `${toText(key, '关系项')} ${safeEntries(value).length}项`;
            const textValue = toText(value, '');
            return textValue ? `${toText(key, '关系项')} ${textValue}` : '';
          })
          .filter(Boolean)
          .join(' / ');
        const editableValue = safeOrgName
          ? makeInlineEditableValue(relationValue, {
              path: ['org', safeOrgName, '关系', relationName, relationField],
              kind: 'string',
              rawValue: relationValue,
            })
          : htmlEscape(relationValue);
        return {
          title: relationMeta.name,
          desc: `<strong>${editableValue}</strong>${detailText ? `<small>${htmlEscape(detailText)}</small>` : ''}`,
          className: relationMeta.className || '',
        };
      }), 'dossier-list--compact dossier-list--relations');
    }

    function buildFactionDossierModal(snapshot, previewKey = '所属势力详细页') {
      const currentFactionName = snapshot.势力[0] ? snapshot.势力[0][0] : '';
      const currentFactionRole = snapshot.势力[0] ? toText(deepGet(snapshot.势力[0][1], '身份', '无'), '无') : '未加入';
      const currentFactionPower = snapshot.势力[0] ? toText(deepGet(snapshot.势力[0][1], '权限级', 0), '0') : '0';
      const activeCharKey = resolveSnapshotCharKey(snapshot, toText(snapshot.activeName, '')) || toText(snapshot.activeName, '');
      const currentFactionPath = currentFactionName && activeCharKey ? ['char', activeCharKey, '社交', '势力', currentFactionName] : [];
      const currentFactionEntry = currentFactionName
        ? (snapshot.orgEntries.find(([name]) => name === currentFactionName) || [currentFactionName, {}])
        : ['', {}];
      const factionRows = snapshot.势力.length ? snapshot.势力 : [['未加入势力', { 身份: '无', 权限级: 0 }]];
      const title = previewKey === '我的阵营详情' ? '阵营权限' : '所属势力';

      return {
        title,
        summary: '当前角色在各势力中的身份、权限与阵营事务。',
        body: `
          <div class="archive-modal-grid dossier-shell dossier-shell--faction">
            <div class="archive-card dossier-card dossier-card--faction-list">
              <div class="archive-card-head">
                <div class="archive-card-title">所属势力列表</div>
                <span class="dossier-pill ${snapshot.势力.length ? 'live' : 'warn'}">${snapshot.势力.length ? `已加入 ${snapshot.势力.length}` : '未加入'}</span>
              </div>
              <div class="dossier-list dossier-list--factions">
                ${factionRows.map(([name, info], idx) => {
                  const factionPath = activeCharKey && name !== '未加入势力' ? ['char', activeCharKey, '社交', '势力', name] : [];
                  const identityValue = toText(info && info['身份'], '无');
                  const powerValue = toNumber(info && info['权限级'], 0);
                  return `
                    <div class="dossier-list-row faction-row ${idx === 0 ? 'highlight' : ''}">
                      <b>${htmlEscape(name)}</b>
                      <span>
                        身份：${factionPath.length
                          ? makeInlineEditableValue(identityValue, {
                              path: [...factionPath, '身份'],
                              kind: 'string',
                              rawValue: identityValue,
                            })
                          : htmlEscape(identityValue)}
                        / 权限级：${factionPath.length
                          ? makeInlineEditableValue(String(powerValue), {
                              path: [...factionPath, '权限级'],
                              kind: 'number',
                              rawValue: powerValue,
                              editorMeta: { min: 0, integer: true, hint: '最小 0 · 整数' },
                            })
                          : htmlEscape(String(powerValue))}
                      </span>
                    </div>
                  `;
                }).join('')}
              </div>
            </div>
            <div class="archive-card dossier-card dossier-card--faction-profile">
              <div class="archive-card-head">
                <div>
                  <div class="archive-card-title">当前阵营档案</div>
                  <div class="dossier-head-name">${htmlEscape(currentFactionName || '未加入势力')}</div>
                </div>
                <span class="dossier-pill ${currentFactionName ? 'live' : 'warn'}">${htmlEscape(currentFactionRole)}</span>
              </div>
              <section class="dossier-section">
                <div class="dossier-section-title">身份定位</div>
                ${makeDossierRows([
                  { label: '当前所属', value: htmlEscape(currentFactionName || '无') },
                  { label: '身份', value: currentFactionPath.length
                    ? makeInlineEditableValue(currentFactionRole, {
                        path: [...currentFactionPath, '身份'],
                        kind: 'string',
                        rawValue: currentFactionRole,
                      })
                    : htmlEscape(currentFactionRole) },
                  { label: '权限级', value: currentFactionPath.length
                    ? makeInlineEditableValue(currentFactionPower, {
                        path: [...currentFactionPath, '权限级'],
                        kind: 'number',
                        rawValue: toNumber(currentFactionPower, 0),
                        editorMeta: { min: 0, integer: true, hint: '最小 0 · 整数' },
                      })
                    : htmlEscape(currentFactionPower) },
                  { label: '主公开身份', value: activeCharKey
                    ? makeInlineEditableValue(toText(deepGet(snapshot, 'activeChar.社交.主身份', '无'), '无'), {
                        path: ['char', activeCharKey, '社交', '主身份'],
                        kind: 'string',
                        rawValue: toText(deepGet(snapshot, 'activeChar.社交.主身份', '无'), '无'),
                      })
                    : htmlEscape(toText(deepGet(snapshot, 'activeChar.社交.主身份', '无'), '无')) },
                  { label: '当前称号', value: htmlEscape(snapshot.recentTitles[0] || '暂无') },
                  { label: '当前位置', value: htmlEscape(snapshot.currentLoc || '未知') },
                ], 'dossier-row-grid--two')}
              </section>
              <section class="dossier-section">
                <div class="dossier-section-title">阵营关系</div>
                ${buildFactionRelationDossierList(currentFactionName, currentFactionEntry[1] || {}, {
                  max: 6,
                  emptyTitle: '暂无阵营关系',
                  emptyDesc: currentFactionName ? '当前所属势力未记录对外关系。' : '当前角色尚未加入可展示关系的势力。'
                })}
              </section>
            </div>
            ${buildFactionAffairConsoleHtml(snapshot, currentFactionName)}
          </div>
        `
      };
    }

    function buildMapTradeModalOptions(snapshot, dispatchDetail) {
      const detail = dispatchDetail || {};
      const services = normalizeMapDispatchServices(detail);
      const action = toText(detail.action, '');
      const tradeRequest = detail.tradeRequest && typeof detail.tradeRequest === 'object' ? detail.tradeRequest : {};
      const requestAction = toText(tradeRequest.动作, '');
      const npcTarget = toText(detail.npcTarget, '');
      const currentLoc = toText(snapshot && snapshot.currentLoc, '');
      const normalizedLoc = toText(snapshot && snapshot.normalizedLoc, currentLoc);
      const 地点映射 = deepGet(snapshot, 'rootData.world.地点', {});
      const currentLocation = snapshot && snapshot.locationData && typeof snapshot.locationData === 'object'
        ? snapshot.locationData
        : (地点映射 && typeof 地点映射 === 'object'
          ? (地点映射[normalizedLoc] || 地点映射[currentLoc] || {})
          : {});
      const storeMap = currentLocation && typeof currentLocation === 'object' ? (currentLocation.商店 || {}) : {};

      let initialTab = 'tab-shop';
      if (/竞拍|拍卖|auction|bid/i.test(requestAction) || action === 'bid' || services.includes('auction')) {
        initialTab = 'tab-auction';
      } else if ((/出售|卖出|sell/i.test(requestAction) && !toText(tradeRequest.对象, npcTarget)) || action === 'sell') {
        initialTab = 'tab-sell';
      } else if ((requestAction && toText(tradeRequest.对象, npcTarget)) || (action === 'trade' && npcTarget)) {
        initialTab = 'tab-private';
      }

      const target = toText(detail.target, '');
      let preferredStore = '';
      const 地图指定商店 = toText(detail.preferredStore || detail.storeName || '', '');
      if (地图指定商店) {
        preferredStore = 地图指定商店;
      } else if (target && storeMap && typeof storeMap === 'object' && storeMap[target]) {
        preferredStore = target;
      } else if (initialTab === 'tab-shop') {
        const storeNames = Object.keys(storeMap || {});
        if (storeNames.length === 1) preferredStore = storeNames[0];
      }
      const currentDiscountSpirit = normalizeSoulTowerDiscountSpiritRecord(
        deepGet(snapshot, 'activeChar.魂灵塔记录.当前五折魂灵', {}),
      );
      if (
        initialTab === 'tab-shop' &&
        !preferredStore &&
        hasActiveSoulTowerDiscountSpirit(currentDiscountSpirit)
      ) {
        preferredStore = SOUL_TOWER_DISCOUNT_STORE_NAME;
      }

      return {
        initialTab,
        prefillNpc: initialTab === 'tab-private' ? toText(tradeRequest.对象, npcTarget) : '',
        lockNpc: initialTab === 'tab-private' && !!toText(tradeRequest.对象, npcTarget),
        preferredStore: toText(tradeRequest.目标, preferredStore) || preferredStore,
        prefillAction: requestAction,
        prefillItem: toText(tradeRequest.物品, ''),
        prefillQty: Math.max(1, toNumber(tradeRequest.数量, 1)),
        prefillPrice: Math.max(0, toNumber(tradeRequest.价格, 0)),
        autoExecute: tradeRequest.自动执行 === true || /auto|ready|执行|成交|确认/.test(toText(tradeRequest.状态, ''))
      };
    }

