      顶层卡片.style.maxWidth = `${maxWidth}px`;
      顶层卡片.style.maxHeight = `${maxHeight}px`;
      顶层卡片.style.left = '0px';
      顶层卡片.style.top = '0px';
      顶层卡片.style.setProperty('z-index', 顶层浮窗层级, 'important');
